/**
 * BigCommerce Compatibility Layer
 *
 * Provides backward-compatible exports that wrap the SDK with the same
 * interface as the original inline theme code. This enables gradual migration
 * from inline implementations to SDK.
 *
 * Usage:
 * ```ts
 * import { createBigCommerceCompat } from '@swiftotter/omniguide-bigcommerce/compat';
 *
 * const compat = createBigCommerceCompat({
 *   apiBaseUrl: 'https://verdict.swiftotter.com',
 *   websiteId: 'https://mystore.com/',
 * });
 *
 * // Use compatibility exports
 * const { loadAnsweredIntents, PlatformAdapter, ChatWebSocket } = compat;
 * ```
 */

import {
  // Storage
  LocalStorageAdapter,
  MemoryStorageAdapter,
  AnsweredIntentsStorage,
  SessionStorage as SDKSessionStorage,
  type StorageAdapter,

  // Platform
  platformRegistry,
  NullPlatformAdapter,

  // WebSocket
  ChatWebSocket as SDKChatWebSocket,
  ProductWebSocket as SDKProductWebSocket,
  CategoryWebSocket as SDKCategoryWebSocket,
  getWebSocketBaseUrl as sdkGetWebSocketBaseUrl,

  // Logger
  createScopedLogger,

  // Types
  type WebSocketMessage,
  type AnsweredIntent as SDKAnsweredIntent,
} from '@swiftotter/omniguide-core';

const log = createScopedLogger('compat');

import {
  createBigCommerceAdapter,
  initBigCommerceAdapter as sdkInitBigCommerceAdapter,
} from './adapter.js';

import type { BigCommerceAdapterConfig } from './types.js';

// =========================================
// Types
// =========================================

export interface CompatConfig extends BigCommerceAdapterConfig {
  /** Storage key for answered intents (default: 'omniguideAnsweredIntents') */
  answeredIntentsStorageKey?: string;
  /** Storage key for session ID (default: 'omniguide_session_id') */
  sessionStorageKey?: string;
}

/** Legacy answered intent format (from inline code) */
export interface LegacyAnsweredIntent {
  answer_id: string | number;
  answer_text?: string;
  answer?: string;
  is_other?: boolean;
  other_text?: string;
  product_type_id?: number;
}

export interface LegacyAnsweredIntentsMap {
  [questionId: string]: LegacyAnsweredIntent;
}

export interface ApiAnsweredIntent {
  answer_id: string | number;
  answer_text: string;
}

export interface ApiAnsweredIntentsMap {
  [questionId: string]: ApiAnsweredIntent;
}

export interface SessionStorageCompat {
  get: () => string | null;
  update: (sessionId: string) => void;
  clear: () => void;
}

export interface PlatformAdapterCompat {
  getStorefrontToken: () => string | null;
  getStoreHash: () => string | null;
  getGraphQLToken: () => string | null;
  getProductSku: () => string | null;
  hydrateProducts: <T>(products: T[]) => Promise<T[]>;
  hydrateCategories: <T>(categories: T[]) => Promise<T[]>;
  isInitialized: () => boolean;
  getPlatformName: () => string;
}

export interface WebSocketCompatConfig {
  websiteCode?: string;
  onMessage?: (msg: WebSocketMessage) => void;
  onStatusChange?: (status: string) => void;
  onError?: (error: Error) => void;
  maxReconnectAttempts?: number;
  maxBackoffDelay?: number;
  connectionTimeout?: number;
  enableHeartbeat?: boolean;
  heartbeatIntervalMs?: number;
  logPrefix?: string;
}

// =========================================
// Helper: Convert legacy intent to SDK format
// =========================================

function legacyToSdkIntent(questionId: string, legacy: LegacyAnsweredIntent): SDKAnsweredIntent {
  return {
    questionId,
    answerId: String(legacy.answer_id),
    answerText: legacy.answer_text || legacy.answer || '',
    isOther: legacy.is_other,
    otherText: legacy.other_text,
    productTypeId: legacy.product_type_id,
  };
}

function sdkToLegacyIntent(sdk: SDKAnsweredIntent): LegacyAnsweredIntent {
  return {
    answer_id: sdk.answerId,
    answer_text: sdk.answerText,
    is_other: sdk.isOther,
    other_text: sdk.otherText,
    product_type_id: sdk.productTypeId,
  };
}

// =========================================
// Storage Factory with Auto-Fallback
// =========================================

/**
 * Create a storage adapter with automatic fallback to in-memory storage.
 * This handles enterprise environments where localStorage may be blocked.
 *
 * Non-Negotiable #3: Statelessness with Storage Abstraction
 */
function createStorageAdapterWithFallback(): StorageAdapter {
  try {
    const testKey = '__omniguide_storage_test__';
    localStorage.setItem(testKey, 'test');
    localStorage.removeItem(testKey);
    return new LocalStorageAdapter();
  } catch {
    log.warn('localStorage unavailable, using in-memory storage. State will not persist across page refreshes.');
    return new MemoryStorageAdapter();
  }
}

// =========================================
// Compatibility Layer Factory
// =========================================

/** Return type for createBigCommerceCompat */
export interface BigCommerceCompatResult {
  // Config
  apiBaseUrl: string;
  websiteId: string;

  // Storage
  ANSWERED_INTENTS_STORAGE_KEY: string;
  loadAnsweredIntents: (productTypeId?: number | string | null) => LegacyAnsweredIntentsMap;
  saveAnsweredIntents: (intents: LegacyAnsweredIntentsMap) => void;
  clearAnsweredIntents: () => void;
  removeAnsweredIntents: (questionIds: string[]) => void;
  getAnsweredIntentsForApi: (productTypeId?: number | string | null) => ApiAnsweredIntentsMap;
  isDiscoveryQuestionId: (questionId: string | number) => boolean;
  toDiscoveryId: (id: string | number) => string;

  // Session
  SessionStorage: SessionStorageCompat;
  getSessionId: () => string;
  clearSessionId: () => void;
  updateSessionId: (newSessionId: string) => void;

  // Platform
  PlatformAdapter: PlatformAdapterCompat;
  initBigCommerceAdapter: (overrideConfig?: Partial<BigCommerceAdapterConfig>) => ReturnType<typeof sdkInitBigCommerceAdapter>;

  // WebSocket helpers
  getWebSocketBaseUrl: () => string;

  // WebSocket factory functions
  createChatWebSocket: (wsConfig?: WebSocketCompatConfig) => SDKChatWebSocket;
  createProductWebSocket: (wsConfig?: WebSocketCompatConfig) => SDKProductWebSocket;
  createCategoryWebSocket: (wsConfig?: WebSocketCompatConfig) => SDKCategoryWebSocket;

  // Re-exports for direct SDK usage
  LocalStorageAdapter: typeof LocalStorageAdapter;
  platformRegistry: typeof platformRegistry;
  createBigCommerceAdapter: typeof createBigCommerceAdapter;
}

/**
 * Create a BigCommerce compatibility layer
 *
 * This factory creates all the backward-compatible exports needed to migrate
 * from inline theme code to the SDK.
 */
export function createBigCommerceCompat(config: CompatConfig): BigCommerceCompatResult {
  const {
    apiBaseUrl = 'https://verdict.swiftotter.com',
    websiteId = '',
    answeredIntentsStorageKey = 'omniguideAnsweredIntents',
    sessionStorageKey = 'omniguide_session_id',
    ...adapterConfig
  } = config;

  // =========================================
  // Storage Setup (with auto-fallback)
  // =========================================

  // Non-Negotiable #3: Use auto-fallback storage adapter
  const storageAdapter = createStorageAdapterWithFallback();

  // Use type assertion to satisfy TypeScript's literal type requirement
  const intentsStorage = new AnsweredIntentsStorage(
    storageAdapter,
    answeredIntentsStorageKey as 'omniguideAnsweredIntents'
  );
  const sessionStorage = new SDKSessionStorage(
    storageAdapter,
    sessionStorageKey as 'omniguide_session_id'
  );

  // =========================================
  // Storage Compatibility Functions
  // =========================================

  const ANSWERED_INTENTS_STORAGE_KEY = answeredIntentsStorageKey;

  const loadAnsweredIntents = (productTypeId: number | string | null = null): LegacyAnsweredIntentsMap => {
    try {
      const productTypeNum = productTypeId !== null ? Number(productTypeId) : undefined;
      const sdkIntents = intentsStorage.load(productTypeNum);

      // Convert SDK format to legacy format
      const legacy: LegacyAnsweredIntentsMap = {};
      for (const [key, value] of Object.entries(sdkIntents)) {
        legacy[key] = sdkToLegacyIntent(value);
      }
      return legacy;
    } catch (e) {
      log.warn('Failed to load answered intents from storage:', e);
      return {};
    }
  };

  const saveAnsweredIntents = (intents: LegacyAnsweredIntentsMap): void => {
    try {
      // Convert legacy format to SDK format and save
      const sdkIntents: Record<string, SDKAnsweredIntent> = {};
      for (const [questionId, legacy] of Object.entries(intents)) {
        sdkIntents[questionId] = legacyToSdkIntent(questionId, legacy);
      }
      intentsStorage.save(sdkIntents);
    } catch (e) {
      log.warn('Failed to save answered intents to storage:', e);
    }
  };

  const clearAnsweredIntents = (): void => {
    try {
      intentsStorage.clear();
    } catch (e) {
      log.warn('Failed to clear answered intents from storage:', e);
    }
  };

  const removeAnsweredIntents = (questionIds: string[]): void => {
    try {
      intentsStorage.remove(questionIds);
    } catch (e) {
      log.warn('Failed to remove answered intents from storage:', e);
    }
  };

  const getAnsweredIntentsForApi = (productTypeId: number | string | null = null): ApiAnsweredIntentsMap => {
    const productTypeNum = productTypeId !== null ? Number(productTypeId) : undefined;
    return intentsStorage.toApiFormat(productTypeNum);
  };

  const isDiscoveryQuestionId = (questionId: string | number): boolean => {
    const idStr = String(questionId);
    return idStr.startsWith('discovery_') || idStr.startsWith('dynamic_');
  };

  const toDiscoveryId = (id: string | number): string => {
    const idStr = String(id);
    if (idStr.startsWith('discovery_') || idStr.startsWith('dynamic_') || idStr.startsWith('intent_')) {
      return idStr;
    }
    return `discovery_${id}`;
  };

  // =========================================
  // Session Storage Compatibility
  // =========================================

  const SessionStorage: SessionStorageCompat = {
    get: () => sessionStorage.get(),
    update: (sessionId: string) => sessionStorage.update(sessionId),
    clear: () => sessionStorage.clear(),
  };

  // =========================================
  // Session Helper Functions
  // =========================================

  const getSessionId = (): string => {
    return SessionStorage.get() || '';
  };

  const clearSessionId = (): void => {
    SessionStorage.clear();
  };

  const updateSessionId = (newSessionId: string): void => {
    if (!newSessionId || typeof newSessionId !== 'string') {
      return;
    }

    const currentSessionId = SessionStorage.get();
    if (currentSessionId !== newSessionId) {
      log.debug('Updating session ID from server:', newSessionId);
      SessionStorage.update(newSessionId);

      // Notify global listeners if available
      if (typeof window !== 'undefined') {
        const win = window as unknown as Record<string, unknown>;
        if (typeof win['loadAISessionId'] === 'function') {
          (win['loadAISessionId'] as (id: string) => void)(newSessionId);
        }
      }
    }
  };

  // =========================================
  // Platform Adapter Compatibility
  // =========================================

  const PlatformAdapter: PlatformAdapterCompat = {
    getStorefrontToken: () => {
      const adapter = platformRegistry.get();
      return adapter?.getCredentials?.()['storefrontToken'] ?? null;
    },

    getStoreHash: () => {
      const adapter = platformRegistry.get();
      return adapter?.getCredentials?.()['storeHash'] ?? null;
    },

    getGraphQLToken: () => {
      const adapter = platformRegistry.get();
      const creds = adapter?.getCredentials?.() ?? {};
      return creds['graphQLToken'] ?? creds['storefrontToken'] ?? null;
    },

    getProductSku: () => {
      const adapter = platformRegistry.get();
      return adapter?.getProductSku?.() ?? null;
    },

    hydrateProducts: async <T>(products: T[]): Promise<T[]> => {
      const adapter = platformRegistry.get();
      if (!adapter?.hydrateProducts) {
        log.warn('Platform adapter not initialized for product hydration');
        return products;
      }
      return adapter.hydrateProducts(products as never) as Promise<T[]>;
    },

    hydrateCategories: async <T>(categories: T[]): Promise<T[]> => {
      const adapter = platformRegistry.get();
      if (!adapter?.hydrateCategories) {
        log.warn('Platform adapter not initialized for category hydration');
        return categories;
      }
      return adapter.hydrateCategories(categories as never) as Promise<T[]>;
    },

    isInitialized: () => {
      const adapter = platformRegistry.get();
      return adapter !== NullPlatformAdapter && adapter?.isInitialized?.() !== false;
    },

    getPlatformName: () => {
      const adapter = platformRegistry.get();
      return adapter?.getPlatformName?.() ?? 'unknown';
    },
  };

  // =========================================
  // Adapter Initialization
  // =========================================

  const initBigCommerceAdapter = (overrideConfig: Partial<BigCommerceAdapterConfig> = {}) => {
    const finalConfig = {
      apiBaseUrl,
      websiteId,
      ...adapterConfig,
      ...overrideConfig,
    };

    const adapter = sdkInitBigCommerceAdapter(finalConfig);
    log.debug('BigCommerce adapter initialized via SDK');
    return adapter;
  };

  // =========================================
  // WebSocket Helpers
  // =========================================

  const getWebSocketBaseUrl = (): string => {
    return sdkGetWebSocketBaseUrl(apiBaseUrl);
  };

  // =========================================
  // WebSocket Factory Functions
  // =========================================

  /**
   * Create a ChatWebSocket instance with compat configuration
   */
  const createChatWebSocket = (wsConfig: WebSocketCompatConfig = {}) => {
    const ws = new SDKChatWebSocket({
      apiBaseUrl,
      websiteCode: wsConfig.websiteCode || websiteId,
      sessionId: getSessionId(),
      onMessage: wsConfig.onMessage || (() => {}),
      onStatusChange: wsConfig.onStatusChange || (() => {}),
      onError: wsConfig.onError || (() => {}),
      maxReconnectAttempts: wsConfig.maxReconnectAttempts,
      maxBackoffDelay: wsConfig.maxBackoffDelay,
      connectionTimeout: wsConfig.connectionTimeout,
    });

    ws.setOnSessionIdUpdate((newSessionId: string) => {
      updateSessionId(newSessionId);
    });

    // Add _send method for backward compatibility
    (ws as unknown as Record<string, unknown>)['_send'] = (message: Record<string, unknown>) => {
      ws.sendQuery(message['content'] as string, message);
    };

    return ws;
  };

  /**
   * Create a ProductWebSocket instance with compat configuration
   */
  const createProductWebSocket = (wsConfig: WebSocketCompatConfig = {}) => {
    const ws = new SDKProductWebSocket({
      apiBaseUrl,
      websiteCode: wsConfig.websiteCode || websiteId,
      sessionId: getSessionId(),
      onMessage: wsConfig.onMessage || (() => {}),
      onStatusChange: wsConfig.onStatusChange || (() => {}),
      onError: wsConfig.onError || (() => {}),
      maxReconnectAttempts: wsConfig.maxReconnectAttempts,
      maxBackoffDelay: wsConfig.maxBackoffDelay,
      connectionTimeout: wsConfig.connectionTimeout,
    });

    ws.setOnSessionIdUpdate((newSessionId: string) => {
      updateSessionId(newSessionId);
    });

    return ws;
  };

  /**
   * Create a CategoryWebSocket instance with compat configuration
   */
  const createCategoryWebSocket = (wsConfig: WebSocketCompatConfig = {}) => {
    const ws = new SDKCategoryWebSocket({
      apiBaseUrl,
      websiteCode: wsConfig.websiteCode || websiteId,
      sessionId: getSessionId(),
      onMessage: wsConfig.onMessage || (() => {}),
      onStatusChange: wsConfig.onStatusChange || (() => {}),
      onError: wsConfig.onError || (() => {}),
      maxReconnectAttempts: wsConfig.maxReconnectAttempts,
      maxBackoffDelay: wsConfig.maxBackoffDelay,
      connectionTimeout: wsConfig.connectionTimeout,
    });

    ws.setOnSessionIdUpdate((newSessionId: string) => {
      updateSessionId(newSessionId);
    });

    return ws;
  };

  // =========================================
  // Return All Exports
  // =========================================

  return {
    // Config
    apiBaseUrl,
    websiteId,

    // Storage
    ANSWERED_INTENTS_STORAGE_KEY,
    loadAnsweredIntents,
    saveAnsweredIntents,
    clearAnsweredIntents,
    removeAnsweredIntents,
    getAnsweredIntentsForApi,
    isDiscoveryQuestionId,
    toDiscoveryId,

    // Session
    SessionStorage,
    getSessionId,
    clearSessionId,
    updateSessionId,

    // Platform
    PlatformAdapter,
    initBigCommerceAdapter,

    // WebSocket helpers
    getWebSocketBaseUrl,

    // WebSocket factory functions
    // Use these to create WebSocket instances: const ws = compat.createChatWebSocket({...})
    createChatWebSocket,
    createProductWebSocket,
    createCategoryWebSocket,

    // Re-exports for direct SDK usage
    LocalStorageAdapter,
    platformRegistry,
    createBigCommerceAdapter,
  };
}

// =========================================
// Type Exports
// =========================================

/** @deprecated Use BigCommerceCompatResult instead */
export type BigCommerceCompat = BigCommerceCompatResult;
