/**
 * BCCategoryGuideContainer — Category guide assistant for BigCommerce themes.
 *
 * Ported from theme `category-recommendations/CategoryAssistant.jsx`.
 * Orchestrates side-by-side layout of BCCategoryRecommendations + SearchChatPanel.
 */

import React, { useCallback, useMemo, useState, useEffect, useRef } from 'react';
import { createScopedLogger } from '@swiftotter/omniguide-core';
import { SearchChatPanel, useOmniguideContext, useFeatureStatus } from '@swiftotter/omniguide-react';
import { useSessionInit } from '../hooks/useSessionInit.js';
import { useBCSearchChat } from '../hooks/useBCSearchChat.js';
import { useAnalyticsTracking } from '../hooks/useAnalyticsTracking.js';
import { useUserConsent } from '../hooks/useUserConsent.js';
import { useFeedbackWidget } from '../hooks/useFeedbackWidget.js';
import { BCCategoryRecommendations } from './BCCategoryRecommendations.js';
import { buildBCHydrationConfig } from '../hooks/buildHydrationConfig.js';
import { fetchProductUrlsBySkus } from '../services/productUrls.js';

const log = createScopedLogger('BCCategoryGuideContainer');

// ── Types ──────────────────────────────────────────────────────────

export interface BCCategoryGuideContainerProps {
  graphqlToken?: string;
}

// ── Component ──────────────────────────────────────────────────────

export function BCCategoryGuideContainer(
  _props: BCCategoryGuideContainerProps,
): JSX.Element | null {
  const { config, platformAdapter, consentService } = useOmniguideContext();
  // Used by SearchChatPanel to map SKU→URL so parseMarkdown can inject data-omniguide-sku
  // on plain markdown links, enabling inline-link click tracking (rec_source=chat_msg).
  const hydrationConfig = useMemo(
    () => buildBCHydrationConfig(config, platformAdapter),
    [config, platformAdapter],
  );
  const fetchProductUrls = useCallback(
    (skus: string[]) => fetchProductUrlsBySkus(skus, hydrationConfig),
    [hydrationConfig],
  );
  const featureStatus = useFeatureStatus(config.websiteId);
  const { callbacks, consent } = config;
  const { trackFeedback, trackScrollForMore, trackScrollStarted, trackInlineProductLink } = useAnalyticsTracking({ websiteId: config.websiteId });
  const handleInlineProductLinkClick = useCallback(
    (data: { sku: string; href: string; messageId?: string; queryContext: string }) => {
      trackInlineProductLink({
        sku: data.sku,
        productUrl: data.href,
        messageId: data.messageId,
        recPageArea: 'category-page-content',
        queryContext: data.queryContext,
      });
    },
    [trackInlineProductLink],
  );
  const handleFeedbackSubmitted = useCallback(({ entityId, vote }: { entityId: string; vote: number }) => {
    trackFeedback({
      messageId: entityId,
      feedbackType: vote > 0 ? 'thumbs_up' : 'thumbs_down',
      turnNumber: 0,
    });
  }, [trackFeedback]);
  const FeedbackWidgetComponent = useFeedbackWidget({
    onFeedbackSubmitted: handleFeedbackSubmitted,
  });
  const [showResults, setShowResults] = useState(false);
  const [resultsLoading, setResultsLoading] = useState(false);
  const [chatCollapsed, setChatCollapsed] = useState(true);
  const [suggestedQuestions, setSuggestedQuestions] = useState<string[]>([]);

  // Auto-collapse chat when results are loaded (not just loading)
  useEffect(() => {
    if (showResults && !resultsLoading) {
      setChatCollapsed(true);
    }
  }, [showResults, resultsLoading]);

  // The chat socket connects to /ws/search/<sessionId>; an empty session id
  // makes that /ws/search/ and the backend rejects the handshake with 403.
  // Initialize the session first (as BCSearchContainer does) and feed it to the
  // chat hook, instead of relying on a localStorage value that is absent on a
  // fresh category-page visit.
  const { sessionId } = useSessionInit();

  const {
    messages,
    sendMessage,
    isLoading,
    pipelineStatus,
    connectionStatus,
    hasAttemptedConnection,
    reconnectInfo,
    connect,
    sendIntentAnswer,
    sendClarificationAnswer,
    handleResetChat,
  } = useBCSearchChat({ autoConnect: false, sessionId });

  // Connect once the session is ready (page-embedded, no modal gate). Connecting
  // before the session id exists opens /ws/search/ with no session → 403.
  const connectCalledRef = useRef(false);
  useEffect(() => {
    if (sessionId && !connectCalledRef.current) {
      connectCalledRef.current = true;
      connect().catch((err: unknown) => {
        log.error('WebSocket connect failed:', err);
      });
    }
  }, [sessionId, connect]);

  // Consent state (two-tier model)
  const { analytics, advertising, websiteConsent, omniguideConsent } = useUserConsent();
  const consentEnabled = analytics && advertising;

  const handleToggleConsent = useCallback(async () => {
    try {
      if (consentService && sessionId && websiteConsent) {
        await consentService.updatePreferences(sessionId, !omniguideConsent);
      }
    } catch (error) {
      log.error('Failed to update consent preferences:', error);
    }
  }, [consentService, sessionId, websiteConsent, omniguideConsent]);

  const handleOpenSupport = useCallback(() => {
    callbacks?.onOpenSupport?.();
  }, [callbacks]);

  const privacySettingsProps = sessionId
    ? {
        sessionId,
        privacyPolicyUrl: consent?.privacyPolicyUrl ?? '/privacy-policy',
        onOpenSupport: handleOpenSupport,
        consentEnabled: consent?.enabled ? consentEnabled : undefined,
        onToggleConsent: consent?.enabled ? handleToggleConsent : undefined,
        consentDisabled: consent?.enabled ? !websiteConsent : undefined,
      }
    : undefined;

  // Wrap sendMessage to include category context
  const handleSendMessage = useCallback(
    (content: string) => {
      const categoryUrl = config.categoryUrl ?? window.location.pathname;
      sendMessage(content, { category_url: categoryUrl, limit_to_entity: 1 });
    },
    [sendMessage, config.categoryUrl],
  );

  const handleIntentAnswer = useCallback(
    (answerText: string, answerId: string | number) => {
      sendIntentAnswer(answerText, String(answerId));
    },
    [sendIntentAnswer],
  );

  const handleCustomIntentAnswer = useCallback(
    (customText: string) => handleSendMessage(customText),
    [handleSendMessage],
  );

  const handleClarificationAnswer = useCallback(
    (answerText: string, optionId: string | number, paramName: string) => {
      sendClarificationAnswer(answerText, String(optionId), paramName);
    },
    [sendClarificationAnswer],
  );

  const handleCustomClarificationAnswer = useCallback(
    (customText: string) => handleSendMessage(customText),
    [handleSendMessage],
  );

  const handleShowResults = useCallback((showing: boolean, loading = false) => {
    setShowResults(showing);
    setResultsLoading(loading);
  }, []);

  const handleSuggestedQuestionsLoad = useCallback((questions: string[]) => {
    setSuggestedQuestions(questions.slice(0, 2));
  }, []);

  const handleChatCollapseToggle = useCallback(() => {
    setChatCollapsed((prev) => !prev);
  }, []);

  const handleScrollForMoreTapped = useCallback(
    (messageId: string) => trackScrollForMore({ messageId }),
    [trackScrollForMore],
  );
  const handleScrollStarted = useCallback(
    (messageId: string) => trackScrollStarted({ messageId }),
    [trackScrollStarted],
  );

  // Hide while pending or when AI is disabled (gate must be after all hooks)
  if (!featureStatus || featureStatus.aiDisabled) {
    return null;
  }

  // Container class - only stack when results are loaded (not loading)
  const containerClassName =
    showResults && !resultsLoading
      ? 'omniguide-cr-assistant omniguide-cr-assistant--stacked'
      : 'omniguide-cr-assistant';

  const getChatPanelClassName = () => {
    const baseClass = 'omniguide-cr-assistant__chat';
    if (showResults && !resultsLoading) {
      return chatCollapsed
        ? `${baseClass} ${baseClass}--below-collapsed`
        : `${baseClass} ${baseClass}--below`;
    }
    return baseClass;
  };

  const questionnaireClassName =
    showResults && !resultsLoading
      ? 'omniguide-cr-assistant__questionnaire omniguide-cr-assistant__questionnaire--full'
      : 'omniguide-cr-assistant__questionnaire';

  return (
    <div className={containerClassName}>
      <div className={questionnaireClassName}>
        <BCCategoryRecommendations
          onShowResults={handleShowResults}
          onSuggestedQuestionsLoad={handleSuggestedQuestionsLoad}
        />
      </div>

      <div className={getChatPanelClassName()}>
        <SearchChatPanel
          messages={messages}
          onSendMessage={handleSendMessage}
          isLoading={isLoading}
          pipelineStatus={pipelineStatus}
          connectionStatus={hasAttemptedConnection ? connectionStatus : undefined}
          onRetryConnection={connect}
          reconnectInfo={reconnectInfo}
          onIntentAnswer={handleIntentAnswer}
          onCustomIntentAnswer={handleCustomIntentAnswer}
          onClarificationAnswer={handleClarificationAnswer}
          onCustomClarificationAnswer={handleCustomClarificationAnswer}
          isCollapsed={chatCollapsed}
          onCollapseToggle={handleChatCollapseToggle}
          variant="category"
          suggestedQuestions={suggestedQuestions}
          onResetChat={handleResetChat}
          FeedbackWidgetComponent={FeedbackWidgetComponent}
          privacySettingsProps={privacySettingsProps}
          onScrollForMoreTapped={handleScrollForMoreTapped}
          onScrollStarted={handleScrollStarted}
          onInlineProductLinkClick={handleInlineProductLinkClick}
          fetchProductUrls={fetchProductUrls}
        />
      </div>
    </div>
  );
}
