/**
 * Category WebSocket for category recommendations
 *
 * Extends BaseWebSocket with category-specific functionality:
 * - Category recommendation requests
 * - Discovery question flow
 */

import { BaseWebSocket, getWebSocketBaseUrl } from '../websocket.js';
import type { WebSocketConfig, WebSocketMessage } from '../types.js';
import type { FirstAnswer } from './ProductWebSocket.js';

export interface CategoryWebSocketConfig extends Omit<WebSocketConfig, 'logPrefix'> {
  /** Base URL for the Omniguide API */
  apiBaseUrl: string;
}

export interface AnsweredIntents {
  [questionId: string]: {
    answer_id: string | number;
    answer_text?: string;
    answer?: string;
  };
}

/**
 * WebSocket manager for category recommendations
 */
export class CategoryWebSocket extends BaseWebSocket {
  private apiBaseUrl: string;

  constructor(config: CategoryWebSocketConfig) {
    super({
      ...config,
      // Category-specific settings
      enableHeartbeat: true,
      heartbeatIntervalMs: 5000,
      maxReconnectAttempts: 3,
      maxBackoffDelay: 10000,
      logPrefix: '[CategoryWebSocket]',
    });

    this.apiBaseUrl = config.apiBaseUrl;
  }

  /**
   * Get WebSocket URL for category recommendations
   */
  protected getWebSocketUrl(): string {
    const baseUrl = getWebSocketBaseUrl(this.apiBaseUrl);
    return `${baseUrl}/ws/category-recommendations/${this.sessionId}`;
  }

  /**
   * Handle category-specific messages
   */
  protected override handleMessage(msg: WebSocketMessage): void {
    this.onMessage(msg);
  }

  /**
   * Send start message to begin conversational flow
   */
  sendStartMessage(categoryUrl: string, firstAnswer?: FirstAnswer): void {
    const message: Record<string, unknown> = {
      type: 'start',
      category_url: categoryUrl,
    };

    if (firstAnswer) {
      message['first_answer'] = {
        question_id: firstAnswer.questionId,
        answer_id: firstAnswer.answerId,
        answer_text: firstAnswer.answerText,
      };
    }

    this.send(message);
  }

  /**
   * Send resume message to continue from a stored session
   */
  sendResumeMessage(categoryUrl: string, answeredIntents: AnsweredIntents = {}): void {
    this.send({
      type: 'resume',
      category_url: categoryUrl,
      answered_intents: answeredIntents,
    });
  }

  /**
   * Send answer for subsequent questions
   */
  sendAnswerMessage(questionId: string, answerId: string | null, answerText: string): void {
    if (!this.isConnected() || !this.ws) {
      throw new Error('WebSocket not connected');
    }

    this.ws.send(
      JSON.stringify({
        type: 'answer',
        question_id: questionId,
        answer_id: answerId,
        answer_text: answerText,
      })
    );
  }

  /**
   * Send recommendation request (legacy - for batch submission)
   */
  sendRecommendationRequest(
    categoryUrl: string,
    answeredIntents: AnsweredIntents,
    options: { maxResults?: number; generateCards?: boolean } = {}
  ): void {
    this.send({
      type: 'get_recommendations',
      category_url: categoryUrl,
      answered_intents: answeredIntents,
      max_results: options.maxResults ?? 3,
      generate_cards: options.generateCards ?? false,
    });
  }
}
