/**
 * useBCCategoryWebSocket — BC-specific wrapper around SDK useCategoryWebSocket.
 *
 * Ported from theme `category-recommendations/hooks/useCategoryWebSocket.js`.
 * Creates DI objects (hydration, wsFactory, storageAdapter) from OmniguideProvider
 * context and delegates to the SDK hook.
 *
 * Supports both conversational and non-conversational (traditional) flows.
 */

import { useMemo } from 'react';
import {
  useCategoryWebSocket,
  type CategoryHydration,
  type CategoryWebSocketFactory,
  type CategoryWebSocketInstance,
  type DiscoveryAnswerStorageAdapter,
  type AnsweredIntentEntry,
} from '@swiftotter/omniguide-react';
import {
  CategoryWebSocket as SDKCategoryWebSocket,
  AnsweredIntentsStorage,
  LocalStorageAdapter,
  createScopedLogger,
  getRegistrySessionId,
  type AnsweredIntent,
} from '@swiftotter/omniguide-core';
import { useOmniguideContext } from '@swiftotter/omniguide-react';
import { hydrateProducts, type HydrationConfig } from '../services/hydration.js';
import { buildBCHydrationConfig } from './buildHydrationConfig.js';

const log = createScopedLogger('useBCCategoryWebSocket');

// ── Types ──────────────────────────────────────────────────────────

export interface UseBCCategoryWebSocketOptions {
  productTypeId?: number | string | null;
}

// ── Hook ───────────────────────────────────────────────────────────

export function useBCCategoryWebSocket({
  productTypeId = null,
}: UseBCCategoryWebSocketOptions = {}) {
  const { config, platformAdapter } = useOmniguideContext();

  // Hydration config
  const hydrationConfig = useMemo<HydrationConfig>(
    () => buildBCHydrationConfig(config, platformAdapter),
    [config, platformAdapter],
  );

  // DI: Hydration
  const hydration = useMemo<CategoryHydration>(() => ({
    hydrateProducts: async (products) => {
      if (!products || products.length === 0) return [];
      try {
        return await hydrateProducts(hydrationConfig, products);
      } catch (error) {
        log.warn('Failed to hydrate products, using original data:', error);
        return products;
      }
    },
  }), [hydrationConfig]);

  // DI: WebSocket factory
  const wsFactory = useMemo<CategoryWebSocketFactory>(() => ({
    create: (wsConfig) => {
      const ws = new SDKCategoryWebSocket({
        apiBaseUrl: config.apiBaseUrl,
        websiteCode: config.websiteId,
        sessionId: getRegistrySessionId(config.websiteId) ?? undefined,
        ...wsConfig,
      });
      return ws as unknown as CategoryWebSocketInstance;
    },
  }), [config.apiBaseUrl, config.websiteId]);

  // DI: Storage adapter
  const storageKey = config.storageKeys?.answeredIntents ?? 'omniguideAnsweredIntents';
  const storageAdapter = useMemo<DiscoveryAnswerStorageAdapter>(() => {
    const storage = new AnsweredIntentsStorage(
      new LocalStorageAdapter(),
      storageKey as 'omniguideAnsweredIntents',
    );
    return {
      load: (ptId) => {
        const raw = storage.load(ptId != null ? Number(ptId) : undefined);
        const result: Record<string, AnsweredIntentEntry> = {};
        for (const [key, value] of Object.entries(raw)) {
          result[key] = {
            question_id: value.questionId,
            answer_id: String(value.answerId),
            answer_text: value.answerText ?? '',
            is_other: value.isOther ?? false,
            question: null,
          };
        }
        return result;
      },
      save: (intents) => {
        const sdkIntents: Record<string, AnsweredIntent> = {};
        for (const [key, entry] of Object.entries(intents)) {
          sdkIntents[key] = {
            questionId: entry.question_id,
            answerId: entry.answer_id ?? '',
            answerText: entry.answer_text,
            isOther: entry.is_other,
            productTypeId: productTypeId != null ? Number(productTypeId) : undefined,
          };
        }
        storage.save(sdkIntents);
      },
      toDiscoveryId: (id) => id.startsWith('discovery_') ? id : `discovery_${id}`,
      getForApi: (ptId) => {
        const raw = storage.toApiFormat(ptId != null ? Number(ptId) : undefined);
        const result: Record<string, Record<string, unknown>> = {};
        for (const [key, value] of Object.entries(raw)) {
          result[key] = value as Record<string, unknown>;
        }
        return result;
      },
    };
  }, [storageKey, productTypeId]);

  return useCategoryWebSocket({
    hydration,
    wsFactory,
    storageAdapter,
    productTypeId,
  });
}
