/**
 * Event Service
 *
 * Sends tracking/analytics events to the Omniguide backend.
 * Provides queuing, periodic flush, beacon-on-unload, retry, and
 * localStorage persistence so that no events are lost — even during
 * page navigation or intermittent network failures.
 *
 * This replaces the per-theme EventTracker; projects only need a thin
 * dataLayer interceptor and a simple analytics adapter — all backend
 * delivery and reliability concerns live here in the SDK.
 */

import { API_ENDPOINTS } from '../constants.js';
import { getCurrentPage } from '../current-page.js';
import { createScopedLogger } from '../logger.js';
import { getPageContext } from '../page-context.js';
import type { ConsentService } from './consent.js';

const log = createScopedLogger('EventService');

// =========================================
// Types
// =========================================

export interface EventServiceConfig {
  /** Omniguide backend base URL */
  apiBaseUrl: string;
  /** Consent service for analytics gating */
  consentService: ConsentService;
  /** Website identifier */
  websiteId?: string;
  /** Flush interval in ms (default: 5000) */
  flushInterval?: number;
  /** Maximum events per flush batch (default: 50) */
  batchSize?: number;
  /** Maximum retry attempts before discarding (default: 3) */
  maxRetries?: number;
  /** Maximum queue size (default: 200) */
  maxQueueSize?: number;
  /** Storefront token for BigCommerce auth headers */
  storefrontToken?: string;
  /** Store hash for BigCommerce auth headers */
  storeHash?: string;
}

export interface SendEventsParams {
  events: Record<string, unknown>[];
  sessionId: string;
  websiteId: string;
  conversationId?: string;
  storefrontToken?: string;
  storeHash?: string;
}

interface QueuedEvent {
  data: Record<string, unknown>;
  attempts: number;
  added_at: number;
}

// =========================================
// EventService
// =========================================

const STORAGE_KEY = 'omniguide_event_queue';
const MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours
// Chrome's quota for in-flight keepalive request bodies is 64KB total (shared
// across all keepalive requests on the page). Stay comfortably under it —
// body.length counts UTF-16 code units, so multi-byte chars inflate actual bytes.
const KEEPALIVE_BODY_LIMIT = 56 * 1024;

export class EventService {
  private apiBaseUrl: string;
  private consentService: ConsentService;
  private websiteId: string;
  private flushInterval: number;
  private batchSize: number;
  private maxRetries: number;
  private maxQueueSize: number;
  private storefrontToken?: string;
  private storeHash?: string;

  private queue: QueuedEvent[] = [];
  private flushTimer: ReturnType<typeof setInterval> | null = null;
  private isFlushing = false;

  // Session context — updated externally via updateContext()
  private sessionId: string | null = null;
  private conversationId: string | null = null;
  private messageId: string | null = null;

  // Bound handlers for cleanup
  private boundVisibilityHandler: () => void;
  private boundPagehideHandler: () => void;

  constructor(config: EventServiceConfig) {
    this.apiBaseUrl = config.apiBaseUrl.replace(/\/$/, '');
    this.consentService = config.consentService;
    this.websiteId = config.websiteId ?? '';
    this.flushInterval = config.flushInterval ?? 5000;
    this.batchSize = config.batchSize ?? 50;
    this.maxRetries = config.maxRetries ?? 3;
    this.maxQueueSize = config.maxQueueSize ?? 200;
    this.storefrontToken = config.storefrontToken;
    this.storeHash = config.storeHash;

    this.boundVisibilityHandler = this.handleVisibilityChange.bind(this);
    this.boundPagehideHandler = this.handlePagehide.bind(this);

    this.loadQueue();
    this.startFlushTimer();
    this.setupUnloadHandlers();
  }

  // ── Public API ──────────────────────────────────────────────────

  /**
   * Queue a tracking event for backend delivery.
   * Events are batched and flushed periodically, or via beacon on page unload.
   */
  track(eventName: string, data: Record<string, unknown> = {}): void {
    const eventData: Record<string, unknown> = {
      event: eventName,
      timestamp: new Date().toISOString(),
      ...data,
    };

    if (this.messageId) {
      eventData['message_id'] = eventData['message_id'] ?? this.messageId;
    }

    this.queue.push({
      data: eventData,
      attempts: 0,
      added_at: Date.now(),
    });

    // Trim queue if too large (drop oldest)
    if (this.queue.length > this.maxQueueSize) {
      const removed = this.queue.splice(0, this.queue.length - this.maxQueueSize);
      log.warn(`Queue exceeded max size, dropped ${removed.length} oldest events`);
    }

    this.saveQueue();
    this.scheduleMicrotaskKick();
  }

  // Click-driven events race navigation. Periodic flush (every flushInterval)
  // and setTimeout-based debounces fire too late — the browser starts
  // navigation right after the click handler returns, before any macrotask.
  //
  // Microtasks run between the end of the current task and the next macrotask
  // (and before navigation default-actions are dispatched). Initiating the
  // fetch in a microtask means the request is on the wire by the time the
  // browser tears the page down. `keepalive: true` (in sendBatch) keeps it
  // alive past unload.
  //
  // Bails when consent isn't initialized yet or canSendAnalytics is false —
  // the event is already persisted in localStorage and the periodic flush
  // (or the next page's EventService.loadQueue) will pick it up.
  private scheduleMicrotaskKick(): void {
    queueMicrotask(() => { this.tryKick(); });
  }

  private tryKick(): void {
    if (this.queue.length === 0 || this.isFlushing) return;
    if (!this.sessionId) return;
    if (!this.consentService.canSendAnalytics()) return;

    this.isFlushing = true;
    const batch = this.queue.splice(0, this.batchSize);
    this.saveQueue();

    const eventDataToSend = batch.map(e => e.data);
    this.sendBatch(eventDataToSend)
      .then(() => { this.isFlushing = false; })
      .catch((error) => {
        log.warn('Kick fetch failed, requeuing:', error);
        for (const queuedEvent of batch) {
          queuedEvent.attempts++;
          if (queuedEvent.attempts < this.maxRetries) {
            this.queue.push(queuedEvent);
          }
        }
        this.saveQueue();
        this.isFlushing = false;
      });
  }

  /**
   * Update session context. Call when conversation starts, session changes, etc.
   */
  updateContext(updates: {
    sessionId?: string;
    conversationId?: string;
    messageId?: string;
    websiteId?: string;
    storefrontToken?: string;
    storeHash?: string;
  }): void {
    if (updates.sessionId !== undefined) this.sessionId = updates.sessionId;
    if (updates.conversationId !== undefined) this.conversationId = updates.conversationId;
    if (updates.messageId !== undefined) this.messageId = updates.messageId;
    if (updates.websiteId !== undefined) this.websiteId = updates.websiteId;
    if (updates.storefrontToken !== undefined) this.storefrontToken = updates.storefrontToken;
    if (updates.storeHash !== undefined) this.storeHash = updates.storeHash;
  }

  /**
   * Flush queued events to the backend.
   * Called automatically by the flush timer — can also be called manually.
   */
  async flush(): Promise<void> {
    if (this.queue.length === 0 || this.isFlushing) return;

    // Don't flush until we have a session ID — events stay queued for next flush
    if (!this.sessionId) {
      log.debug('Flush deferred: no sessionId yet');
      return;
    }

    this.isFlushing = true;

    const batch = this.queue.splice(0, this.batchSize);
    this.saveQueue();

    try {
      await this.consentService.ensureInitialized(this.sessionId);

      if (!this.consentService.canSendAnalytics()) {
        // Requeue — we'll try again next flush when consent may be granted
        this.queue.unshift(...batch);
        this.saveQueue();
        return;
      }

      const eventDataToSend = batch.map(e => e.data);
      await this.sendBatch(eventDataToSend);
    } catch (error) {
      log.error('Flush failed:', error);

      // Requeue with incremented attempt count
      for (const queuedEvent of batch) {
        queuedEvent.attempts++;
        if (queuedEvent.attempts < this.maxRetries) {
          this.queue.push(queuedEvent);
        } else {
          log.error(`Event "${queuedEvent.data['event']}" dropped after ${this.maxRetries} attempts`);
        }
      }
      this.saveQueue();
    } finally {
      this.isFlushing = false;
    }
  }

  /**
   * Send remaining events via navigator.sendBeacon (for page unload).
   * Returns true if the beacon was sent successfully.
   */
  sendBeacon(): boolean {
    if (this.queue.length === 0) return true;

    if (!this.sessionId || !this.consentService.canSendAnalytics()) {
      // Keep in queue for next page load (via localStorage)
      this.saveQueue();
      return false;
    }

    const eventDataToSend = this.queue.map(e => e.data);
    const payload = JSON.stringify(this.buildPayload(eventDataToSend));

    const success = typeof navigator !== 'undefined' && navigator.sendBeacon
      ? navigator.sendBeacon(
          this.getEventUrl(),
          new Blob([payload], { type: 'application/json' }),
        )
      : false;

    if (success) {
      this.queue = [];
      this.saveQueue();
    }

    return success;
  }

  /**
   * Legacy method — send events immediately (no queueing).
   * Kept for backward compatibility with existing callers.
   */
  async sendEvents(params: SendEventsParams): Promise<void> {
    const { events, sessionId, websiteId, conversationId, storefrontToken, storeHash } = params;

    if (!sessionId || !events || events.length === 0) return;

    try {
      await this.consentService.ensureInitialized(sessionId);

      if (!this.consentService.canSendAnalytics()) return;

      const url = this.getEventUrl();
      const currentPage = getCurrentPage();

      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
      };
      if (storefrontToken) {
        headers['X-Storefront-Token'] = storefrontToken;
      }
      if (storeHash) {
        headers['X-Storefront-Hash'] = storeHash;
      }

      await fetch(url, {
        method: 'POST',
        headers,
        body: JSON.stringify({
          session_id: sessionId,
          website_code: websiteId,
          events,
          current_page: currentPage,
          ...(conversationId && { conversation_id: conversationId }),
          page_context: getPageContext(),
        }),
      });
    } catch (error) {
      log.error('Failed to send event batch:', error);
    }
  }

  /**
   * Clean up timers and listeners. Call when the service is no longer needed.
   */
  destroy(): void {
    if (this.flushTimer) {
      clearInterval(this.flushTimer);
      this.flushTimer = null;
    }
    this.removeUnloadHandlers();
    // Best-effort final flush via beacon
    this.sendBeacon();
  }

  /**
   * Get current queue length (for testing / debugging).
   */
  getQueueLength(): number {
    return this.queue.length;
  }

  // ── Private ─────────────────────────────────────────────────────

  private getEventUrl(): string {
    return `${this.apiBaseUrl}${API_ENDPOINTS.EVENT}`;
  }

  private buildPayload(events: Record<string, unknown>[]): Record<string, unknown> {
    return {
      session_id: this.sessionId,
      website_code: this.websiteId,
      conversation_id: this.conversationId,
      message_id: this.messageId,
      current_page: getCurrentPage(),
      events,
      page_context: getPageContext(),
    };
  }

  private async sendBatch(events: Record<string, unknown>[]): Promise<void> {
    const url = this.getEventUrl();
    const payload = this.buildPayload(events);

    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };
    if (this.storefrontToken) {
      headers['X-Storefront-Token'] = this.storefrontToken;
    }
    if (this.storeHash) {
      headers['X-Storefront-Hash'] = this.storeHash;
    }

    // keepalive lets the request complete after the page navigates away —
    // critical for click-driven events where the user is about to leave the page.
    // BUT browsers hard-reject keepalive fetches whose body exceeds the quota
    // (TypeError before the request leaves) — and the retry loop would rebuild
    // the same oversized batch until its events are dropped. Oversized batches
    // fall back to a plain fetch: no survive-navigation guarantee, but they send.
    const body = JSON.stringify(payload);
    const response = await fetch(url, {
      method: 'POST',
      headers,
      body,
      keepalive: body.length <= KEEPALIVE_BODY_LIMIT,
    });

    if (!response.ok) {
      throw new Error(`HTTP ${response.status}`);
    }
  }

  private loadQueue(): void {
    if (typeof localStorage === 'undefined') return;

    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (!stored) return;

      const parsed: QueuedEvent[] = JSON.parse(stored);
      // Filter out events older than 24 hours
      const valid = parsed.filter(e => Date.now() - e.added_at < MAX_AGE_MS);
      if (valid.length > 0) {
        this.queue.push(...valid);
        log.debug(`Loaded ${valid.length} event(s) from storage`);
      }
      // Clear storage after loading
      localStorage.removeItem(STORAGE_KEY);
    } catch {
      // Ignore storage errors
    }
  }

  private saveQueue(): void {
    if (typeof localStorage === 'undefined') return;

    try {
      if (this.queue.length === 0) {
        localStorage.removeItem(STORAGE_KEY);
      } else {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(this.queue));
      }
    } catch {
      // Ignore storage errors (quota exceeded, etc.)
    }
  }

  private startFlushTimer(): void {
    if (this.flushTimer) clearInterval(this.flushTimer);
    this.flushTimer = setInterval(() => { this.flush(); }, this.flushInterval);
  }

  private handleVisibilityChange(): void {
    if (typeof document !== 'undefined' && document.visibilityState === 'hidden') {
      this.sendBeacon();
    }
  }

  private handlePagehide(): void {
    this.sendBeacon();
  }

  private setupUnloadHandlers(): void {
    if (typeof window === 'undefined') return;
    // visibilitychange dispatches on document, not window — wrong target = no fire.
    if (typeof document !== 'undefined') {
      document.addEventListener('visibilitychange', this.boundVisibilityHandler);
    }
    window.addEventListener('pagehide', this.boundPagehideHandler);
  }

  private removeUnloadHandlers(): void {
    if (typeof window === 'undefined') return;
    if (typeof document !== 'undefined') {
      document.removeEventListener('visibilitychange', this.boundVisibilityHandler);
    }
    window.removeEventListener('pagehide', this.boundPagehideHandler);
  }
}

/**
 * Create an EventService instance.
 */
export function createEventService(config: EventServiceConfig): EventService {
  return new EventService(config);
}
