import React, { useState, useEffect, useMemo } from 'react';
import { DiscoveryOptionButton } from './DiscoveryOptionButton.js';

export interface AnswerChoice {
    /** AttributeValue id, e.g. "attrvalue_276447". */
    id: string;
    value: string;
}

export type AutocompleteRenderHint = 'autocomplete' | 'searchable_dropdown';

export interface DiscoveryAutocompleteProps {
    questionId: string;
    choices: AnswerChoice[];
    onSelectChoice: (choice: AnswerChoice) => void;
    selectedValue?: string | null;
    /**
     * Number of quick-pick pills shown before the user types (autocomplete
     * variant only). Choices arrive pre-sorted by popularity, so this is
     * simply the first N.
     */
    topCount?: number;
    /** Cap on the number of matches rendered while filtering. */
    maxResults?: number;
    placeholder?: string;
    /** Label rendered above the filter input (autocomplete variant). */
    filterLabel?: string;
    /**
     * Accessible name for the interactive control — should be the question
     * text so the choice list/combobox is announced with the question rather
     * than a generic group label.
     */
    ariaLabel?: string;
    /**
     * Render variant (SOI-616):
     *  - `'autocomplete'` (default): shows the top `topCount` choices as
     *    pills with an "Or filter it down here" box beneath. Typing replaces
     *    the pills in place with matches; clearing restores the top picks.
     *    Suited to long lists (50-200 values) where common picks should be
     *    one click away.
     *  - `'searchable_dropdown'`: always-open listbox below a filter input,
     *    with keyboard navigation. Suited to ≤30 values.
     */
    renderHint?: AutocompleteRenderHint;
}

function filterChoices(choices: AnswerChoice[], query: string, max: number): AnswerChoice[] {
    const trimmed = query.trim().toLowerCase();
    if (!trimmed) return choices.slice(0, max);
    const matches: AnswerChoice[] = [];
    for (const choice of choices) {
        if (choice.value.toLowerCase().includes(trimmed)) {
            matches.push(choice);
            if (matches.length >= max) break;
        }
    }
    return matches;
}

// ── Variant: top-picks pills + in-place filter (default) ─────────────

interface InlineFilterPillsProps {
    questionId: string;
    choices: AnswerChoice[];
    onSelectChoice: (choice: AnswerChoice) => void;
    selectedValue: string | null;
    topCount: number;
    maxResults: number;
    placeholder: string;
    filterLabel: string;
    ariaLabel?: string;
}

function InlineFilterPills({
    questionId,
    choices,
    onSelectChoice,
    selectedValue,
    topCount,
    maxResults,
    placeholder,
    filterLabel,
    ariaLabel,
}: InlineFilterPillsProps): JSX.Element {
    const [query, setQuery] = useState('');
    const inputId = `omniguide-cfq-filter-${questionId}`;

    // Reset the filter when the question changes (dynamic mode reuses the node).
    useEffect(() => {
        setQuery('');
    }, [questionId]);

    const isFiltering = query.trim().length > 0;
    const results = useMemo(
        () => filterChoices(choices, query, isFiltering ? maxResults : topCount),
        [choices, query, isFiltering, maxResults, topCount],
    );

    return (
        <div className="omniguide-pr-cfq">
            {results.length > 0 ? (
                <div
                    className="omniguide-pr-questionnaire__choices omniguide-pr-cfq__choices"
                    role="radiogroup"
                    aria-label={ariaLabel ?? 'Filtered options'}
                >
                    {results.map((choice) => (
                        <DiscoveryOptionButton
                            key={choice.id}
                            answer={{ id: choice.id, text: choice.value }}
                            isSelected={selectedValue === choice.value}
                            onSelect={() => onSelectChoice(choice)}
                        />
                    ))}
                </div>
            ) : (
                <div className="omniguide-pr-cfq__no-results" role="status">
                    No matches
                </div>
            )}

            <div className="omniguide-pr-cfq__filter">
                <label className="omniguide-pr-cfq__filter-label" htmlFor={inputId}>
                    {filterLabel}
                </label>
                <input
                    id={inputId}
                    type="text"
                    className="omniguide-pr-cfq__filter-input"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder={placeholder}
                    autoComplete="off"
                    aria-label={filterLabel}
                />
            </div>
        </div>
    );
}

// ── Variant: always-open searchable dropdown ─────────────────────────

interface SearchableDropdownProps {
    questionId: string;
    choices: AnswerChoice[];
    onSelectChoice: (choice: AnswerChoice) => void;
    selectedValue: string | null;
    maxResults: number;
    placeholder: string;
    ariaLabel?: string;
}

function SearchableDropdown({
    questionId,
    choices,
    onSelectChoice,
    selectedValue,
    maxResults,
    placeholder,
    ariaLabel,
}: SearchableDropdownProps): JSX.Element {
    const [query, setQuery] = useState(selectedValue ?? '');
    // Start collapsed when a value is already restored — otherwise the list
    // would open pre-filtered to the single chosen option on mount.
    const [isOpen, setIsOpen] = useState(false);
    const [highlightedIndex, setHighlightedIndex] = useState(0);
    const listboxId = `omniguide-autocomplete-listbox-${questionId}`;

    useEffect(() => {
        setQuery(selectedValue ?? '');
        setIsOpen(false);
        setHighlightedIndex(0);
    }, [questionId, selectedValue]);

    const results = useMemo(
        () => filterChoices(choices, query, maxResults),
        [choices, query, maxResults],
    );

    // Clamp the highlight when the results window shrinks. Keyed off
    // results.length only — reading highlightedIndex via the functional
    // updater avoids re-subscribing (and the update-loop risk) on every move.
    useEffect(() => {
        setHighlightedIndex((i) => (i >= results.length ? 0 : i));
    }, [results.length]);

    const showList = isOpen && results.length > 0;

    const handleSelect = (choice: AnswerChoice) => {
        setQuery(choice.value);
        setIsOpen(false);
        onSelectChoice(choice);
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            setIsOpen(true);
            setHighlightedIndex((i) => Math.min(i + 1, results.length - 1));
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            setHighlightedIndex((i) => Math.max(i - 1, 0));
        } else if (e.key === 'Enter') {
            e.preventDefault();
            const choice = results[highlightedIndex];
            if (choice) handleSelect(choice);
        } else if (e.key === 'Escape') {
            setIsOpen(false);
        }
    };

    return (
        <div className="omniguide-pr-autocomplete omniguide-pr-autocomplete--searchable-dropdown">
            <input
                type="text"
                className="omniguide-pr-autocomplete__input"
                value={query}
                onChange={(e) => {
                    setQuery(e.target.value);
                    setIsOpen(true);
                    setHighlightedIndex(0);
                }}
                onFocus={() => setIsOpen(true)}
                onKeyDown={handleKeyDown}
                placeholder={placeholder}
                role="combobox"
                aria-label={ariaLabel}
                aria-expanded={showList}
                aria-controls={listboxId}
                aria-autocomplete="list"
                aria-activedescendant={
                    showList && results[highlightedIndex]
                        ? `${listboxId}-option-${results[highlightedIndex].id}`
                        : undefined
                }
            />
            {showList && (
                <ul id={listboxId} role="listbox" className="omniguide-pr-autocomplete__list">
                    {results.map((choice, index) => (
                        <li
                            key={choice.id}
                            id={`${listboxId}-option-${choice.id}`}
                            role="option"
                            aria-selected={index === highlightedIndex}
                            className={
                                index === highlightedIndex
                                    ? 'omniguide-pr-autocomplete__option omniguide-pr-autocomplete__option--highlighted'
                                    : 'omniguide-pr-autocomplete__option'
                            }
                            onMouseDown={(e) => e.preventDefault()}
                            onClick={() => handleSelect(choice)}
                            onMouseEnter={() => setHighlightedIndex(index)}
                        >
                            {choice.value}
                        </li>
                    ))}
                </ul>
            )}
            {isOpen && query.trim() && results.length === 0 && (
                <div className="omniguide-pr-autocomplete__no-results" role="status">No matches</div>
            )}
        </div>
    );
}

export function DiscoveryAutocomplete({
    questionId,
    choices,
    onSelectChoice,
    selectedValue = null,
    topCount = 5,
    maxResults = 12,
    placeholder,
    filterLabel = 'Or filter it down here',
    ariaLabel,
    renderHint = 'autocomplete',
}: DiscoveryAutocompleteProps): JSX.Element {
    if (renderHint === 'searchable_dropdown') {
        return (
            <SearchableDropdown
                questionId={questionId}
                choices={choices}
                onSelectChoice={onSelectChoice}
                selectedValue={selectedValue}
                maxResults={maxResults}
                placeholder={placeholder ?? 'Filter options…'}
                ariaLabel={ariaLabel}
            />
        );
    }

    return (
        <InlineFilterPills
            questionId={questionId}
            choices={choices}
            onSelectChoice={onSelectChoice}
            selectedValue={selectedValue}
            topCount={topCount}
            maxResults={maxResults}
            placeholder={placeholder ?? 'Type to filter…'}
            filterLabel={filterLabel}
            ariaLabel={ariaLabel}
        />
    );
}
