import React from 'react';
import { ErrorIcon, RefreshIcon } from './Icons.js';

export interface LoadingStateProps {
    statusMessage?: string;
}

/**
 * Loading state component for fit evaluation.
 */
export const LoadingState = ({ statusMessage }: LoadingStateProps): JSX.Element => (
    <div className="omniguide-pr-loading">
        <div className="omniguide-pr-loading__spinner" />
        <p className="omniguide-pr-loading__text">{statusMessage || 'Evaluating product fit...'}</p>
    </div>
);

export interface ErrorStateProps {
    error?: { message?: string; code?: string } | null;
    onRetry?: () => void;
}

function isConnectionError(error?: { code?: string } | null): boolean {
    return error?.code === 'WEBSOCKET_ERROR';
}

/**
 * Error state component for fit evaluation.
 */
export const ErrorState = ({ error, onRetry }: ErrorStateProps): JSX.Element => {
    const connectionIssue = isConnectionError(error);
    const title = connectionIssue ? 'Unable to connect' : 'Something went wrong';
    const text = connectionIssue
        ? 'The service is currently unavailable. Please try again in a moment.'
        : 'We encountered an error while processing your request. Please try again.';

    return (
        <div className="omniguide-pr-error">
            <div className="omniguide-pr-error__icon-wrapper">
                <ErrorIcon />
            </div>
            <h3 className="omniguide-pr-error__title">{title}</h3>
            <p className="omniguide-pr-error__text">{text}</p>
            <button
                type="button"
                className="omniguide-pr-error__retry-btn"
                onClick={onRetry}
            >
                <RefreshIcon />
                <span>Try Again</span>
            </button>
        </div>
    );
};
