/**
 * Shared feature status watcher for integration classes.
 *
 * Subscribes to the feature status registry and toggles `display: none`
 * on a DOM container when `aiDisabled` is true.
 */

import { getFeatureStatus, onFeatureStatusChange } from '@swiftotter/omniguide-core';

export interface FeatureStatusWatcherResult {
  unsubscribe: () => void;
}

export function watchFeatureStatus(
  websiteId: string,
  container: HTMLElement,
): FeatureStatusWatcherResult {
  const applyVisibility = (aiDisabled: boolean) => {
    container.style.display = aiDisabled ? 'none' : '';
  };

  // Apply current status immediately if available
  const current = getFeatureStatus(websiteId);
  if (current) {
    applyVisibility(current.aiDisabled);
  }

  // Subscribe to future changes
  const unsubscribe = onFeatureStatusChange(websiteId, (status) => {
    applyVisibility(status.aiDisabled);
  });

  return { unsubscribe };
}
