import React, { memo } from 'react';

export interface DiscoveryAnswer {
    id: string;
    text: string;
    [key: string]: unknown;
}

export interface DiscoveryOptionButtonProps {
    answer: DiscoveryAnswer;
    isSelected: boolean;
    onSelect: (answer: DiscoveryAnswer) => void;
}

const CheckIcon = () => (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
        <polyline points="20 6 9 17 4 12" />
    </svg>
);

export const DiscoveryOptionButton = memo(function DiscoveryOptionButton({ answer, isSelected, onSelect }: DiscoveryOptionButtonProps): JSX.Element {
    return (
        <button
            type="button"
            className={`omniguide-pr-option-pill ${isSelected ? 'omniguide-pr-option-pill--selected' : ''}`}
            onClick={() => onSelect(answer)}
            aria-pressed={isSelected}
        >
            <div className="omniguide-pr-option-pill__checkbox">
                <div className={`omniguide-pr-option-pill__checkbox-inner ${isSelected ? 'omniguide-pr-option-pill__checkbox-inner--selected' : ''}`}>
                    {isSelected && <CheckIcon />}
                </div>
            </div>
            <span className="omniguide-pr-option-pill__text">{answer.text}</span>
        </button>
    );
});
