import React, { memo } from 'react';
import { formatPrice } from '@swiftotter/omniguide-core';
import { BenefitsList } from '../discovery/BenefitsList.js';
import { ReviewInsightsToggle } from '../discovery/ReviewInsightsToggle.js';
import { ProductTag } from '../discovery/ProductTag.js';
import { parseMarkdownToHtml } from '../../utils/markdown.js';
import { UseCaseRatings } from './UseCaseRatings.js';
import type { UseCase } from './UseCaseRatings.js';

export interface CategoryProduct {
    id?: string | number;
    name?: string;
    display_name?: string;
    product_line?: string;
    price?: number | string | { value?: number };
    retail_price?: number | string | { value?: number };
    url?: string;
    path?: string;
    image_url?: string;
    imageUrl?: string;
    defaultImage?: { url?: string };
    sku?: string;
    tag?: { type: string };
    review_insights?: {
        average_rating?: number;
        review_count?: number;
        summary?: string;
        likes?: string[];
    };
    brand?: { name?: string };
    benefits?: string[];
    use_cases?: UseCase[];
    why?: string;
    critical_attributes?: string[];
}

export interface CategoryProductCardProps {
    product: CategoryProduct;
    index: number;
    /** Fallback image URL when product has no image (DI for site config) */
    fallbackImage?: string;
    /** Show "Top Pick" / "Runner-Up" tags (default: true) */
    showProductTags?: boolean;
    /** Click handler for the "View Now" link (analytics DI) */
    onViewClick?: () => void;
}

/**
 * CategoryProductCard displays a product with AI-generated content.
 * Handles both raw API data and BigCommerce hydrated data.
 */
export const CategoryProductCard = memo(function CategoryProductCard({ product, index, fallbackImage = '', showProductTags = true, onViewClick }: CategoryProductCardProps): JSX.Element | null {
    if (!product) return null;

    const {
        name,
        display_name,
        product_line,
        price,
        retail_price,
        url,
        path,
        image_url,
        imageUrl,
        defaultImage,
        tag,
        review_insights,
        brand,
        benefits = [],
        use_cases = [],
        why,
    } = product;

    // Resolve display name — prefer full name (includes brand) per SOI-271
    const displayName = name ?? display_name;

    // Resolve brand name (API format: product_line string, BC format: brand.name)
    const rawBrand = product_line ?? brand?.name ?? '';
    const brandName = rawBrand;
    // Strip brand prefix from display name to avoid visual duplication (brand shown on its own line)
    const cleanDisplayName = (rawBrand && displayName && displayName.toLowerCase().startsWith(rawBrand.toLowerCase() + ' '))
        ? displayName.slice(rawBrand.length).trimStart() || displayName
        : displayName;

    // Resolve image URL (API format: image_url, BC format: imageUrl or defaultImage.url)
    const resolvedImageUrl = image_url ?? imageUrl ?? defaultImage?.url ?? fallbackImage;

    // Resolve product URL (API format: url, BC format: path)
    const productUrl = url ?? path;

    // Resolve price (API or BC format)
    const resolvedPrice = typeof price === 'object' ? price?.value : price;
    const resolvedRetailPrice = typeof retail_price === 'object' ? retail_price?.value : retail_price;

    // Get rating from review insights
    const averageRating = review_insights?.average_rating ?? 0;
    const reviewCount = review_insights?.review_count ?? 0;

    // Determine tag to display (use tag from API or fallback based on index)
    const displayTag = showProductTags ? (tag ?? { type: index === 0 ? 'recommended' : 'runner_up' }) : null;

    return (
        <div className="omniguide-cr-card">
            {/* Image Section with Badge */}
            <div className="omniguide-cr-card__image-section">
                <img
                    src={resolvedImageUrl}
                    alt={cleanDisplayName}
                    className="omniguide-cr-card__image"
                    onError={(e) => {
                        if (fallbackImage) {
                            (e.target as HTMLImageElement).src = fallbackImage;
                        }
                    }}
                />
                {displayTag && <ProductTag tag={displayTag} classPrefix="omniguide-cr-card__badge" />}
            </div>

            {/* Product Info */}
            <div className="omniguide-cr-card__content">
                <div className="omniguide-cr-card__columns-container">
                    <div className="omniguide-cr-card__columns-text">
                        <div className="omniguide-cr-card__brand-row">
                            <p className="omniguide-cr-card__brand">{brandName}</p>
                            <h3 className="omniguide-cr-card__name">{cleanDisplayName}</h3>
                        </div>
                        <div className="omniguide-cr-card__price-group">
                            <span className="omniguide-cr-card__price">{formatPrice(resolvedPrice)}</span>
                            {resolvedRetailPrice && Number(resolvedRetailPrice) > Number(resolvedPrice) && (
                                <span className="omniguide-cr-card__price omniguide-cr-card__price--original">{formatPrice(resolvedRetailPrice)}</span>
                            )}
                        </div>
                    </div>
                    <div className="omniguide-cr-card__actions">
                        <a href={productUrl} className="omniguide-cr-card__view-btn" onClick={onViewClick}>
                            View Now
                            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                                <path d="M6 12L10 8L6 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                            </svg>
                        </a>
                        {averageRating > 0 && (
                            <ReviewInsightsToggle
                                rating={averageRating}
                                reviewCount={reviewCount}
                                summary={review_insights?.summary}
                                likes={review_insights?.likes}
                            />
                        )}
                    </div>
                </div>
            </div>

            {/* Divider */}
            <div className="omniguide-cr-card__divider" />

            {/* Benefits and Use Cases - Two Column Layout */}
            {(benefits.length > 0 || use_cases.length > 0) && (
                <div className="omniguide-cr-card__benefits-row">
                    {/* Benefits Column */}
                    <div className="omniguide-cr-card__benefits">
                        <BenefitsList benefits={benefits} maxItems={4} showTitle={true} />
                    </div>

                    {/* Use Cases Column */}
                    {use_cases.length > 0 && (
                        <div className="omniguide-cr-card__use-cases">
                            <UseCaseRatings useCases={use_cases} maxItems={4} />
                        </div>
                    )}
                </div>
            )}

            {/* Why This Product Box */}
            {why && (
                <div className="omniguide-cr-card__why-section">
                    <div className="omniguide-cr-card__why-box">
                        <h4 className="omniguide-cr-card__why-title">
                            Why this product would work better for you:
                        </h4>
                        <p
                            className="omniguide-cr-card__why-text"
                            dangerouslySetInnerHTML={parseMarkdownToHtml(why)}
                        />
                    </div>
                </div>
            )}
        </div>
    );
});
