import React, { useState } from 'react';

const UNSELECTED = Symbol('unselected');

export interface IntentAnswer {
    id: string | number;
    answer?: string;
    answer_text?: string;
    explanation?: string;
    is_other_option?: boolean;
}

export interface IntentQuestion {
    id?: string | number;
    question_id?: string | number;
    question?: string;
    question_text?: string;
    answers: IntentAnswer[];
    _isDiscoveryQuestion?: boolean;
}

export interface SearchIntentQuestionUIProps {
    intentQuestion: IntentQuestion;
    onAnswerClick: (answerText: string, answerId: string | number, options?: Record<string, unknown>) => void;
    onCustomAnswer: (customText: string) => void;
}

export const SearchIntentQuestionUI: React.FC<SearchIntentQuestionUIProps> = ({
    intentQuestion,
    onAnswerClick,
    onCustomAnswer,
}) => {
    const [customInput, setCustomInput] = useState('');
    const [selectedAnswerId, setSelectedAnswerId] = useState<string | number | symbol>(UNSELECTED);
    const [showOtherInput, setShowOtherInput] = useState(false);
    const [hoveredId, setHoveredId] = useState<string | number | symbol>(UNSELECTED);

    if (!intentQuestion) return null;

    const isDiscoveryQuestion = intentQuestion._isDiscoveryQuestion;
    const hasOtherOption = intentQuestion.answers?.some(a => a.is_other_option);

    const handleAnswerClick = (answer: IntentAnswer) => {
        const answerText = answer.answer_text || answer.answer || '';

        if (answer.is_other_option) {
            setSelectedAnswerId(answer.id);
            setShowOtherInput(true);
            return;
        }

        setSelectedAnswerId(answer.id);
        setShowOtherInput(false);

        if (isDiscoveryQuestion) {
            onAnswerClick(answerText, answer.id, {
                isOtherAnswer: false,
            });
        } else {
            onAnswerClick(answerText, answer.id);
        }
    };

    const handleOtherClick = () => {
        setSelectedAnswerId('other');
        setShowOtherInput(true);
    };

    const handleCustomSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (customInput.trim()) {
            if (isDiscoveryQuestion) {
                const otherAnswer = intentQuestion.answers?.find(a => a.is_other_option);
                if (otherAnswer) {
                    onAnswerClick(customInput.trim(), otherAnswer.id, {
                        isOtherAnswer: true,
                        otherAnswerText: customInput.trim(),
                    });
                } else {
                    onCustomAnswer(customInput.trim());
                }
            } else {
                onCustomAnswer(customInput.trim());
            }
            setCustomInput('');
        }
    };

    return (
        <div className="omniguide-intent-question">
            <div className="omniguide-intent-answers">
                {intentQuestion.answers.map((answer) => {
                    const isSelected = selectedAnswerId === answer.id;
                    const displayText = answer.is_other_option ? 'Other' : (answer.answer_text || answer.answer);

                    return (
                        <button
                            key={answer.id}
                            onClick={() => handleAnswerClick(answer)}
                            className="omniguide-intent-answer-btn"
                            data-selected={isSelected}
                            data-hovered={hoveredId === answer.id}
                            onMouseEnter={() => setHoveredId(answer.id)}
                            onMouseLeave={() => setHoveredId(UNSELECTED)}
                            title={answer.explanation || ''}
                        >
                            {displayText}
                        </button>
                    );
                })}
                {!hasOtherOption && (
                    <button
                        onClick={handleOtherClick}
                        className="omniguide-intent-answer-btn"
                        data-selected={selectedAnswerId === 'other'}
                        data-hovered={hoveredId === 'other'}
                        onMouseEnter={() => setHoveredId('other')}
                        onMouseLeave={() => setHoveredId(UNSELECTED)}
                    >
                        Other
                    </button>
                )}
            </div>
            {showOtherInput && (
                <form onSubmit={handleCustomSubmit} className="omniguide-intent-custom-form">
                    <input
                        type="text"
                        value={customInput}
                        onChange={(e) => setCustomInput(e.target.value)}
                        placeholder="Type your answer..."
                        className="omniguide-intent-custom-input"
                        autoFocus
                    />
                    <button
                        type="submit"
                        disabled={!customInput.trim()}
                        className="omniguide-intent-custom-submit"
                        data-disabled={!customInput.trim()}
                    >
                        Send
                    </button>
                </form>
            )}
        </div>
    );
};
