/**
 * useFeatureStatus — Subscribes to the feature status registry for a given websiteId.
 *
 * Returns `null` while status is pending (e.g. /initialize hasn't completed yet),
 * or the full OmniguideFeatureStatus object once available.
 */

import { useState, useEffect } from 'react';
import { getFeatureStatus, onFeatureStatusChange, type OmniguideFeatureStatus } from '@swiftotter/omniguide-core';

export function useFeatureStatus(websiteId: string): OmniguideFeatureStatus | null {
  const [status, setStatus] = useState<OmniguideFeatureStatus | null>(
    () => getFeatureStatus(websiteId),
  );

  useEffect(() => {
    // Sync in case it changed between render and effect
    const current = getFeatureStatus(websiteId);
    if (current !== null) {
      setStatus(current);
    }

    return onFeatureStatusChange(websiteId, (next) => {
      setStatus((prev) => prev?.aiDisabled === next.aiDisabled ? prev : next);
    });
  }, [websiteId]);

  return status;
}
