/**
 * Shared builder for the BC HydrationConfig consumed by the SDK services.
 *
 * Hoisted here so `useBCSearchChat`, `useBCProductWebSocket`, and
 * `useBCCategoryWebSocket` apply the same direct-GraphQL opt-in derivation.
 */

import type { OmniguideConfig, PlatformAdapter } from '@swiftotter/omniguide-core';
import type { HydrationConfig } from '../services/hydration.js';

export function buildBCHydrationConfig(
  config: OmniguideConfig,
  platformAdapter: PlatformAdapter,
): HydrationConfig {
  const readToken = () => platformAdapter.getCredentials()['graphQLToken'] ?? null;
  const direct = config.directGraphQL;

  return {
    apiBaseUrl: config.apiBaseUrl,
    websiteId: config.websiteId,
    getGraphQLToken: readToken,
    ...(config.productHydrationEndpoint
      ? { productHydrationEndpoint: config.productHydrationEndpoint }
      : {}),
    ...(direct?.enabled
      ? {
          directGraphQL: {
            enabled: true,
            endpoint: direct.endpoint,
            getToken: direct.getToken ?? readToken,
          },
        }
      : {}),
  };
}
