/**
 * @swiftotter/omniguide-bundle
 *
 * Pre-built UMD bundle for Omniguide AI SDK.
 * Works via <script> tag — no build tooling required.
 *
 * Usage:
 *   <link rel="stylesheet" href="omniguide-sdk.css">
 *   <script src="omniguide-sdk.standalone.js"></script>
 *   <script>
 *     Omniguide.init({ websiteId: 'https://mystore.com/' });
 *   </script>
 *
 * Or declaratively:
 *   <script src="omniguide-sdk.standalone.js" data-omniguide-config='{"websiteId":"https://mystore.com/"}'></script>
 */

// Side-effect import: extracts CSS into omniguide-sdk.css
import '@swiftotter/omniguide-styles';

import {
  logger,
  initPreviewFromQueryParam,
  setPreviewApiUrl,
  clearPreviewApiUrl,
  isPreviewMode,
  setCurrentPageOverride,
} from '@swiftotter/omniguide-core';
import type { BundleInitConfig, OmniguideInstance } from './types.js';
import { buildConfig, buildPlatformAdapter } from './defaults.js';
import { autoInit } from './auto-init.js';

// Check query param override before any init() call
initPreviewFromQueryParam();

// Re-export types for advanced consumers
export type { BundleInitConfig, OmniguideInstance } from './types.js';

// Re-export integration classes and utilities for advanced usage
export {
  BCSearchIntegration,
  BCProductFitIntegration,
  BCCategoryGuideIntegration,
  createBigCommerceAdapter,
  initBigCommerceAdapter,
  createBigCommerceCompat,
  LATENCY,
  ResponseTimer,
  createResponseTimer,
} from '@swiftotter/omniguide-bigcommerce';

// Re-export core utilities for theme wrapper files and custom setups
export {
  createSessionService,
  createConsentService,
  NullPlatformAdapter,
  createPlatformAdapter,
  getPageContext,
  capturePageContext,
  trackEvent,
  updateEventContext,
  getConsentState,
} from '@swiftotter/omniguide-core';

export { OmniguideProvider } from '@swiftotter/omniguide-react';

declare const __OMNIGUIDE_VERSION__: string;

/**
 * Get the bundle version.
 */
export function getVersion(): string {
  return __OMNIGUIDE_VERSION__;
}

/**
 * Initialize the Omniguide SDK with a simplified config.
 *
 * This is the primary API for script-tag consumers.
 * It builds the full config, creates a platform adapter,
 * and initializes all enabled feature integrations.
 */
export function init(config: BundleInitConfig): OmniguideInstance {
  if (!config.websiteId) {
    throw new Error('[Omniguide] websiteId is required in config');
  }

  // Set current-page override for mock/dev stores
  if (config.currentPage) {
    setCurrentPageOverride(config.currentPage);
  }

  const omniguideConfig = buildConfig(config);
  const platformAdapter = buildPlatformAdapter(config);

  return autoInit(omniguideConfig, platformAdapter, omniguideConfig.features, config.search, config.pdpWidget, config.plpWidget);
}

// ── Preview mode console API ─────────────────────────────────────────
// Usage: Omniguide.setPreviewApi('https://service-staging.omniguide.ai')
//        Omniguide.clearPreviewApi()
//        Omniguide.isPreviewMode()

export function setPreviewApi(url: string): void {
  setPreviewApiUrl(url);
  // eslint-disable-next-line no-console -- intentional user-visible feedback from Omniguide.setPreviewApi() call
  console.warn('[Omniguide] Preview API set to %s. Reload the page for changes to take effect.', url);
}

export function clearPreviewApi(): void {
  clearPreviewApiUrl();
  // eslint-disable-next-line no-console -- intentional user-visible feedback from Omniguide.clearPreviewApi() call
  console.warn('[Omniguide] Preview API cleared. Reload the page to use the default API.');
}

export { isPreviewMode };

// ── Declarative auto-init ───────────────────────────────────────────
// Scan for <script data-omniguide-config='...'> and call init() automatically.

function declarativeInit(): void {
  const scripts = document.querySelectorAll('script[data-omniguide-config]');

  scripts.forEach((script) => {
    const raw = script.getAttribute('data-omniguide-config');
    if (!raw) return;

    try {
      const config = JSON.parse(raw) as BundleInitConfig;
      init(config);
    } catch (e) {
      logger.error('Failed to parse data-omniguide-config:', e);
    }
  });
}

if (typeof document !== 'undefined') {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', declarativeInit);
  } else {
    // DOM already loaded (script loaded async/defer or at bottom)
    declarativeInit();
  }
}

// ── Global exposure ──────────────────────────────────────────────────
// The UMD build sets window.Omniguide via Vite's lib wrapper, but when
// imported as ESM (e.g. mock-store dev server) we need an explicit assignment.
// IMPORTANT: Only assign if Omniguide doesn't already exist (i.e. ESM mode).
// In UMD mode the wrapper already populated window.Omniguide with all exports;
// overwriting it here would lose the re-exported integration classes/utilities.
if (typeof window !== 'undefined' && !(window as Record<string, unknown>)['Omniguide']) {
  (window as Record<string, unknown>)['Omniguide'] = {
    init,
    getVersion,
    setPreviewApi,
    clearPreviewApi,
    isPreviewMode,
  };
}
