import React, { memo } from 'react';

export interface SearchNavigationButtonsProps {
    canGoUp: boolean;
    canGoDown: boolean;
    onNavigateUp: (e: React.MouseEvent | React.KeyboardEvent) => void;
    onNavigateDown: (e: React.MouseEvent | React.KeyboardEvent) => void;
    currentIndex: number;
    totalCount: number;
    timestamp?: string | number | Date;
    isMobile?: boolean;
}

export const SearchNavigationButtons: React.FC<SearchNavigationButtonsProps> = memo(({
    canGoUp,
    canGoDown,
    onNavigateUp,
    onNavigateDown,
    currentIndex,
    totalCount,
    timestamp,
    isMobile = false,
}) => {
    if (totalCount <= 1) return null;

    const formattedTime = timestamp
        ? new Date(timestamp as string | number).toLocaleTimeString([], {
            hour: '2-digit',
            minute: '2-digit',
        })
        : '';

    const handleNavKeyDown = (e: React.KeyboardEvent, direction: 'up' | 'down') => {
        if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            e.stopPropagation();
            if (direction === 'up') {
                onNavigateUp(e);
            } else if (direction === 'down') {
                onNavigateDown(e);
            }
        }
    };

    const handleUpClick = (e: React.MouseEvent) => {
        e.stopPropagation();
        e.preventDefault();
        onNavigateUp(e);
    };

    const handleDownClick = (e: React.MouseEvent) => {
        e.stopPropagation();
        e.preventDefault();
        onNavigateDown(e);
    };

    if (isMobile) {
        return (
            <nav
                className="omniguide-chat__navigation omniguide-chat__navigation--mobile"
                role="navigation"
                aria-label="Message navigation"
            >
                <div className="omniguide-chat__nav-buttons" role="group" aria-label="Navigate between messages">
                    <button
                        type="button"
                        onClick={handleUpClick}
                        className="omniguide-chat__nav-btn"
                        data-disabled={!canGoUp}
                        aria-disabled={!canGoUp}
                        aria-label={`Previous message (${currentIndex} of ${totalCount})`}
                    >
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" focusable="false">
                            <polyline points="18 15 12 9 6 15"></polyline>
                        </svg>
                    </button>
                    <span className="omniguide-chat__nav-indicator" aria-live="polite">
                        {currentIndex + 1} / {totalCount}
                    </span>
                    <button
                        type="button"
                        onClick={handleDownClick}
                        className="omniguide-chat__nav-btn"
                        data-disabled={!canGoDown}
                        aria-disabled={!canGoDown}
                        aria-label={`Next message (${currentIndex + 2} of ${totalCount})`}
                    >
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" focusable="false">
                            <polyline points="6 9 12 15 18 9"></polyline>
                        </svg>
                    </button>
                </div>
            </nav>
        );
    }

    return (
        <nav
            className="omniguide-chat__navigation"
            role="navigation"
            aria-label="Message navigation"
        >
            <div className="omniguide-chat__nav-buttons" role="group" aria-label="Navigate between messages">
                <button
                    type="button"
                    onClick={handleUpClick}
                    onKeyDown={(e) => handleNavKeyDown(e, 'up')}
                    className="omniguide-chat__nav-btn"
                    data-disabled={!canGoUp}
                    aria-disabled={!canGoUp}
                    aria-label={`Previous message (${currentIndex} of ${totalCount})`}
                >
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" focusable="false">
                        <polyline points="18 15 12 9 6 15"></polyline>
                    </svg>
                </button>
                <button
                    type="button"
                    onClick={handleDownClick}
                    onKeyDown={(e) => handleNavKeyDown(e, 'down')}
                    className="omniguide-chat__nav-btn"
                    data-disabled={!canGoDown}
                    aria-disabled={!canGoDown}
                    aria-label={`Next message (${currentIndex + 2} of ${totalCount})`}
                >
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" focusable="false">
                        <polyline points="6 9 12 15 18 9"></polyline>
                    </svg>
                </button>
            </div>
            {formattedTime && (
                <div className="omniguide-chat__nav-timestamp" aria-live="polite">
                    {formattedTime}
                </div>
            )}
        </nav>
    );
});
