/**
 * Shared utilities for Omniguide SDK
 */

export interface SourceItem {
  type?: string;
  data?: {
    name?: string;
    url?: string;
    [key: string]: unknown;
  };
  [key: string]: unknown;
}

/**
 * Filter out sources that lack required data (name and url).
 * Used by hydration hooks to remove empty/invalid content sources.
 */
export const filterEmptyContent = (sources: SourceItem[]): SourceItem[] =>
  sources.filter((source) => {
    const { data } = source;
    if (!data) return false;
    return !!data.name?.trim() && !!data.url?.trim();
  });

/** Normalize a URL for dedup comparison: trim and strip trailing slash. */
const normalizeUrl = (url: string): string => {
  const trimmed = url.trim();
  return trimmed.endsWith('/') && trimmed.length > 1
    ? trimmed.slice(0, -1)
    : trimmed;
};

/**
 * Deduplicate sources by URL (trailing-slash-insensitive).
 * When two entries share the same normalized URL, the one without a
 * trailing slash is kept.
 *
 * Opt-in only — not called by default. Consumers pass this explicitly
 * if backend dedup is insufficient for their use case.
 */
export const dedupeByUrl = (sources: SourceItem[]): SourceItem[] => {
  const seen = new Map<string, SourceItem>();
  for (const source of sources) {
    const raw = source.data?.url ?? '';
    const key = normalizeUrl(raw);
    if (!key) { seen.set(raw, source); continue; }
    const existing = seen.get(key);
    if (!existing) {
      seen.set(key, source);
    } else {
      // Prefer the entry without a trailing slash
      if (raw.endsWith('/') && !existing.data?.url?.endsWith('/')) continue;
      seen.set(key, source);
    }
  }
  return [...seen.values()];
};

/**
 * Remove redundant content sources when both members of a pair are present.
 * Each pair: [urlToRemove, urlThatMustExist]. Comparison is trailing-slash-insensitive.
 *
 * Opt-in only — consumers configure `redundantContentUrls` in UI config
 * when they have known URL pairs that the backend indexes separately.
 */
export const filterRedundantContent = (
  sources: SourceItem[],
  pairs: [string, string][],
): SourceItem[] => {
  if (!pairs?.length) return sources;
  const normalizedUrls = new Set(sources.map(s => normalizeUrl(s.data?.url ?? '')));
  const toRemove = new Set<string>();
  for (const [removable, required] of pairs) {
    if (normalizedUrls.has(normalizeUrl(required)) && normalizedUrls.has(normalizeUrl(removable))) {
      toRemove.add(normalizeUrl(removable));
    }
  }
  if (toRemove.size === 0) return sources;
  return sources.filter(s => !toRemove.has(normalizeUrl(s.data?.url ?? '')));
};
