/**
 * Response Latency Handling (Non-Negotiable #4)
 *
 * Provides utilities for two-stage latency handling:
 * - 3s → Show "Thinking..." UI
 * - 10s → Hard timeout with retry option
 */

import { LATENCY } from './constants.js';

export type LatencyState = 'idle' | 'waiting' | 'thinking' | 'timeout';

export interface ResponseTimerCallbacks {
  /** Called when entering "thinking" state (after THINKING_THRESHOLD) */
  onThinking?: () => void;
  /** Called when response times out (after RESPONSE_TIMEOUT) */
  onTimeout?: () => void;
  /** Called when timer is cancelled (response received) */
  onCancel?: () => void;
}

export interface ResponseTimerConfig {
  /** Milliseconds before showing "thinking" state (default: 3000) */
  thinkingThreshold?: number;
  /** Milliseconds before timeout (default: 10000) */
  responseTimeout?: number;
}

/**
 * Timer utility for tracking response latency
 *
 * Usage:
 * ```ts
 * const timer = new ResponseTimer({
 *   onThinking: () => setShowThinking(true),
 *   onTimeout: () => setError('Response timed out'),
 * });
 *
 * // When sending a query
 * timer.start();
 *
 * // When receiving any response
 * timer.cancel();
 *
 * // On component unmount
 * timer.destroy();
 * ```
 */
export class ResponseTimer {
  private thinkingTimer: ReturnType<typeof setTimeout> | null = null;
  private timeoutTimer: ReturnType<typeof setTimeout> | null = null;
  private state: LatencyState = 'idle';
  private callbacks: ResponseTimerCallbacks;
  private thinkingThreshold: number;
  private responseTimeout: number;

  constructor(
    callbacks: ResponseTimerCallbacks,
    config: ResponseTimerConfig = {}
  ) {
    this.callbacks = callbacks;
    this.thinkingThreshold = config.thinkingThreshold ?? LATENCY.THINKING_THRESHOLD;
    this.responseTimeout = config.responseTimeout ?? LATENCY.RESPONSE_TIMEOUT;
  }

  /**
   * Start the latency timer (call when sending a query)
   */
  start(): void {
    this.cancel();
    this.state = 'waiting';

    // Start thinking timer (3s)
    this.thinkingTimer = setTimeout(() => {
      this.state = 'thinking';
      this.callbacks.onThinking?.();
    }, this.thinkingThreshold);

    // Start timeout timer (10s)
    this.timeoutTimer = setTimeout(() => {
      this.state = 'timeout';
      this.callbacks.onTimeout?.();
    }, this.responseTimeout);
  }

  /**
   * Cancel the timer (call when any response is received)
   */
  cancel(): void {
    if (this.thinkingTimer) {
      clearTimeout(this.thinkingTimer);
      this.thinkingTimer = null;
    }

    if (this.timeoutTimer) {
      clearTimeout(this.timeoutTimer);
      this.timeoutTimer = null;
    }

    if (this.state !== 'idle') {
      this.state = 'idle';
      this.callbacks.onCancel?.();
    }
  }

  /**
   * Get current latency state
   */
  getState(): LatencyState {
    return this.state;
  }

  /**
   * Check if timer is currently running
   */
  isRunning(): boolean {
    return this.state !== 'idle';
  }

  /**
   * Clean up timers (call on unmount)
   */
  destroy(): void {
    this.cancel();
  }
}

/**
 * Create a response timer with the given callbacks
 */
export function createResponseTimer(
  callbacks: ResponseTimerCallbacks,
  config?: ResponseTimerConfig
): ResponseTimer {
  return new ResponseTimer(callbacks, config);
}
