import React, { useState } from 'react';

const UNSELECTED = Symbol('unselected');

export interface ClarificationOption {
    id: string | number;
    label: string;
    description?: string;
}

export interface ClarificationQuestion {
    id?: string | number;
    message: string;
    param_name: string;
    question?: string;
    question_text?: string;
    options: ClarificationOption[];
}

export interface SearchClarificationQuestionUIProps {
    clarificationQuestion: ClarificationQuestion;
    onAnswerClick: (optionLabel: string, optionId: string | number, paramName: string) => void;
    onCustomAnswer: (customText: string) => void;
}

export const SearchClarificationQuestionUI: React.FC<SearchClarificationQuestionUIProps> = ({
    clarificationQuestion,
    onAnswerClick,
    onCustomAnswer,
}) => {
    const [customInput, setCustomInput] = useState('');
    const [selectedOptionId, setSelectedOptionId] = useState<string | number | symbol>(UNSELECTED);
    const [showOtherInput, setShowOtherInput] = useState(false);
    const [hoveredId, setHoveredId] = useState<string | number | symbol>(UNSELECTED);

    if (!clarificationQuestion) return null;

    const { message, param_name, options } = clarificationQuestion;

    const handleOptionClick = (optionLabel: string, optionId: string | number) => {
        setSelectedOptionId(optionId);
        setShowOtherInput(false);
        onAnswerClick(optionLabel, optionId, param_name);
    };

    const handleOtherClick = () => {
        setSelectedOptionId('other');
        setShowOtherInput(true);
    };

    const handleCustomSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (customInput.trim()) {
            onCustomAnswer(customInput.trim());
            setCustomInput('');
        }
    };

    return (
        <div className="omniguide-intent-question">
            <p className="omniguide-intent-question__text">{message}</p>
            <div className="omniguide-intent-answers">
                {options.map((option) => {
                    const isSelected = selectedOptionId === option.id;
                    return (
                        <button
                            key={option.id}
                            onClick={() => handleOptionClick(option.label, option.id)}
                            className="omniguide-intent-answer-btn"
                            data-selected={isSelected}
                            data-hovered={hoveredId === option.id}
                            onMouseEnter={() => setHoveredId(option.id)}
                            onMouseLeave={() => setHoveredId(UNSELECTED)}
                            title={option.description || ''}
                        >
                            {option.label}
                        </button>
                    );
                })}
                <button
                    onClick={handleOtherClick}
                    className="omniguide-intent-answer-btn"
                    data-selected={selectedOptionId === 'other'}
                    data-hovered={hoveredId === 'other'}
                    onMouseEnter={() => setHoveredId('other')}
                    onMouseLeave={() => setHoveredId(UNSELECTED)}
                >
                    Other
                </button>
            </div>
            {showOtherInput && (
                <form onSubmit={handleCustomSubmit} className="omniguide-intent-custom-form">
                    <input
                        type="text"
                        value={customInput}
                        onChange={(e) => setCustomInput(e.target.value)}
                        placeholder="Type your answer..."
                        className="omniguide-intent-custom-input"
                        autoFocus
                    />
                    <button
                        type="submit"
                        disabled={!customInput.trim()}
                        className="omniguide-intent-custom-submit"
                        data-disabled={!customInput.trim()}
                    >
                        Send
                    </button>
                </form>
            )}
        </div>
    );
};
