import React, { memo } from 'react';

const TAG_LABELS: Record<string, string> = {
    'top-pick': 'Top Pick',
    'runner-up': 'Runner-Up',
};

// Inline SVG icons to avoid lucide-react dependency
const TrophyIcon: React.FC = () => (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: '4px' }}>
        <path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"></path>
        <path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"></path>
        <path d="M4 22h16"></path>
        <path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"></path>
        <path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"></path>
        <path d="M18 2H6v7a6 6 0 0 0 12 0V2Z"></path>
    </svg>
);

const AwardIcon: React.FC = () => (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: '4px' }}>
        <circle cx="12" cy="8" r="6"></circle>
        <path d="M15.477 12.89 17 22l-5-3-5 3 1.523-9.11"></path>
    </svg>
);

const TAG_ICONS: Record<string, React.FC> = {
    'top-pick': TrophyIcon,
    'runner-up': AwardIcon,
};

export interface SearchAITagProps {
    status: string | null;
}

export const SearchAITag: React.FC<SearchAITagProps> = memo(({ status }) => {
    if (!status || !TAG_LABELS[status]) {
        return null;
    }

    const IconComponent = TAG_ICONS[status];
    const className = `omniguide-ai-tag omniguide-ai-tag--${status}`;

    return (
        <span className={className}>
            {IconComponent && <IconComponent />}
            {TAG_LABELS[status]}
        </span>
    );
});

SearchAITag.displayName = 'SearchAITag';
