/**
 * useBCCategoryQuestions — Fetches category questions from REST API.
 *
 * Ported from theme `category-recommendations/hooks/useCategoryQuestions.js`.
 * Uses omniguide-core `fetchCategoryQuestions` with config from OmniguideProvider.
 */

import { useState, useEffect, useCallback } from 'react';
import { fetchCategoryQuestions, createScopedLogger, type DiscoveryQuestion } from '@swiftotter/omniguide-core';
import { useOmniguideContext } from '@swiftotter/omniguide-react';

const log = createScopedLogger('useBCCategoryQuestions');

// ── Types ──────────────────────────────────────────────────────────

export interface CategoryData {
  categoryId: unknown;
  categoryUrl: string;
  categoryName: string;
  productTypeId: unknown;
  productTypeName: string;
  productCount: number;
  suggestedQuestions: string[];
  shortSeoSummary: string;
}

export interface UseBCCategoryQuestionsReturn {
  questions: DiscoveryQuestion[];
  categoryData: CategoryData | null;
  loading: boolean;
  error: Error | null;
  hasQuestions: boolean;
  /** Retry fetching questions after an error */
  retry: () => void;
}

// ── Hook ───────────────────────────────────────────────────────────

export function useBCCategoryQuestions(
  categoryUrl?: string,
): UseBCCategoryQuestionsReturn {
  const { config } = useOmniguideContext();

  const [questions, setQuestions] = useState<DiscoveryQuestion[]>([]);
  const [categoryData, setCategoryData] = useState<CategoryData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);
  const [retryCount, setRetryCount] = useState(0);

  const retry = useCallback(() => setRetryCount((c) => c + 1), []);

  useEffect(() => {
    const loadQuestions = async () => {
      setLoading(true);
      setError(null);

      try {
        const questionConfig = {
          apiBaseUrl: config.apiBaseUrl,
          websiteId: config.websiteId,
        };

        // Use current page URL by default
        const url = categoryUrl ?? window.location.pathname;
        const data = await fetchCategoryQuestions(questionConfig, url);

        setCategoryData({
          categoryId: data['category_id'],
          categoryUrl: (data['category_url'] as string) || url,
          categoryName: data['category_name'] as string,
          productTypeId: data['product_type_id'],
          productTypeName: data['product_type_name'] as string,
          productCount: data['product_count'] as number,
          suggestedQuestions: (data['suggested_questions'] as string[]) || [],
          shortSeoSummary: (data['short_seo_summary'] as string) || '',
        });

        setQuestions(data.questions);
      } catch (err) {
        log.error('Error loading category questions:', err);
        setError(err instanceof Error ? err : new Error(String(err)));
        setQuestions([]);
      } finally {
        setLoading(false);
      }
    };

    loadQuestions();
  }, [categoryUrl, config.apiBaseUrl, config.websiteId, retryCount]);

  return {
    questions,
    categoryData,
    loading,
    error,
    hasQuestions: questions.length > 0,
    retry,
  };
}
