import React, { useEffect, useRef } from 'react';
import { DiscoveryStepIndicator } from './DiscoveryStepIndicator.js';
import type { AnsweredQuestionEntry } from './DiscoveryStepIndicator.js';
import { DiscoveryQuestionStep } from './DiscoveryQuestionStep.js';
import type { DiscoveryQuestion, OtherError } from './DiscoveryQuestionStep.js';
import type { DiscoveryAnswer } from './DiscoveryOptionButton.js';
import type { AnswerChoice } from './DiscoveryAutocomplete.js';

export interface DiscoveryQuestionnaireProps {
    questions: DiscoveryQuestion[];
    currentStep: number;
    answeredIntents: Record<string, { answer: string; answer_id?: string; [key: string]: unknown }>;
    onSelectAnswer: (questionId: string, answer: DiscoveryAnswer) => void;
    /** Critical Filter Question pick — see DiscoveryQuestionStep.onSelectChoice. */
    onSelectChoice?: (questionId: string, choice: AnswerChoice) => void;
    onNext: () => void;
    onPrevious: () => void;
    onSubmit: () => void;
    onStepClick?: (index: number) => void;
    submitButtonText?: string;
    subtitle?: string;
    classPrefix?: string;
    dynamicMode?: boolean;
    answeredQuestions?: AnsweredQuestionEntry[];
    questionNumber?: number;
    onOtherSubmit?: (text: string) => void;
    isOtherProcessing?: boolean;
    otherError?: OtherError | null;
    clarificationPrompt?: string | null;
    onClearOtherError?: () => void;
}

const AIIcon = () => (
    <svg width="20" height="24" viewBox="0 0 20 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <path
            d="M9.9053 2.33347C6.87579 2.33351 4.0579 4.2161 2.89846 7.01495C1.73921 9.81387 2.40038 13.1374 4.54251 15.2796C6.68479 17.4215 10.0084 18.0818 12.8072 16.9225C15.6057 15.7629 17.4886 12.9461 17.4886 9.9168H19.822C19.822 13.0057 18.3397 15.9094 15.9551 17.7633C15.4571 18.1505 15.4825 18.9831 16.0087 19.331C17.5342 20.3398 18.7955 21.7162 19.667 23.3335H16.9042C15.3078 21.2085 12.7666 19.8335 9.90416 19.8335C7.0417 19.8335 4.50051 21.2084 2.90416 23.3335H0.141301C1.01161 21.7185 2.2713 20.3442 3.79397 19.3356C4.32198 18.9857 4.34423 18.1467 3.84182 17.761C3.51005 17.5065 3.19253 17.2291 2.89277 16.9293C0.083256 14.1197 -0.777662 9.79259 0.742864 6.12172C2.26348 2.45101 5.93208 0.000177863 9.9053 0.000137573V2.33347Z"
            fill="currentColor"
        />
        <path
            d="M12.593 0.0502678C13.1243 -0.0167857 13.6839 -0.0167262 14.2154 0.0502678C14.3017 4.62302 15.1984 5.51921 19.7707 5.60561C19.8378 6.13712 19.8377 6.69646 19.7707 7.228C15.1986 7.31439 14.3017 8.21126 14.2154 12.7833C13.6838 12.8504 13.1245 12.8504 12.593 12.7833C12.5066 8.21101 11.6104 7.3143 7.03762 7.228C6.97064 6.69651 6.97054 6.13706 7.03762 5.60561C11.6106 5.5193 12.5067 4.62327 12.593 0.0502678Z"
            fill="currentColor"
        />
    </svg>
);

const ArrowRightIcon = () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <path
            d="M5 12H19M19 12L12 5M19 12L12 19"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        />
    </svg>
);

const ArrowLeftIcon = () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <path
            d="M19 12H5M5 12L12 5M5 12L12 19"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        />
    </svg>
);

export function DiscoveryQuestionnaire({
    questions,
    currentStep,
    answeredIntents,
    onSelectAnswer,
    onSelectChoice,
    onNext,
    onPrevious,
    onSubmit,
    onStepClick,
    submitButtonText = 'See Recommendations',
    subtitle,
    classPrefix = 'omniguide-cr',
    dynamicMode = false,
    answeredQuestions = [],
    questionNumber = 0,
    onOtherSubmit,
    isOtherProcessing = false,
    otherError = null,
    clarificationPrompt = null,
    onClearOtherError,
}: DiscoveryQuestionnaireProps): JSX.Element {
    const currentQuestion = questions[currentStep];
    const currentAnswer = currentQuestion?.id ? answeredIntents[currentQuestion.id] : undefined;
    const isLastStep = currentStep === questions.length - 1;
    const isFirstStep = currentStep === 0;
    const hasSelection = !!currentAnswer;

    const wasPreAnsweredRef = useRef<Record<string, boolean>>({});
    const questionId = currentQuestion?.id;

    useEffect(() => {
        if (questionId && wasPreAnsweredRef.current[questionId] === undefined) {
            wasPreAnsweredRef.current[questionId] = hasSelection;
        }
    }, [questionId, hasSelection]);

    const wasPreAnswered = questionId ? wasPreAnsweredRef.current[questionId] : false;

    const handleNextClick = () => {
        if (isLastStep) {
            onSubmit();
        } else {
            onNext();
        }
    };

    const handleAnswerSelect = (qId: string, answer: DiscoveryAnswer) => {
        onSelectAnswer(qId, answer);

        if (!wasPreAnswered) {
            setTimeout(() => {
                handleNextClick();
            }, 300);
        }
    };

    return (
        <div className={`${classPrefix}-questionnaire`}>
            <div className={`${classPrefix}-questionnaire__header`}>
                <div className={`${classPrefix}-questionnaire__header-row`}>
                    <div className={`${classPrefix}-questionnaire__title-row`}>
                        <div className={`${classPrefix}-questionnaire__icon`}>
                            <AIIcon />
                        </div>
                        <h2 className={`${classPrefix}-questionnaire__title`}>{currentQuestion?.question || 'Loading...'}</h2>
                    </div>
                    <DiscoveryStepIndicator
                        currentStep={currentStep}
                        totalSteps={questions.length}
                        answeredIntents={answeredIntents}
                        questions={questions}
                        onStepClick={onStepClick}
                        classPrefix={classPrefix}
                        showAnswerPills={false}
                        dynamicMode={dynamicMode}
                        answeredQuestions={answeredQuestions}
                        questionNumber={questionNumber}
                    />
                </div>
                {subtitle && (
                    <p className={`${classPrefix}-questionnaire__subtitle`}>
                        {subtitle}
                    </p>
                )}
            </div>

            {currentQuestion && (
                <DiscoveryQuestionStep
                    question={currentQuestion}
                    selectedAnswer={currentAnswer}
                    onSelectAnswer={(answer) => handleAnswerSelect(currentQuestion.id, answer)}
                    onSelectChoice={onSelectChoice ? (choice) => onSelectChoice(currentQuestion.id, choice) : undefined}
                    onOtherSubmit={onOtherSubmit ? (_questionId, text) => onOtherSubmit(text) : undefined}
                    isOtherProcessing={isOtherProcessing}
                    otherError={otherError}
                    clarificationPrompt={clarificationPrompt}
                    onClearOtherError={onClearOtherError}
                />
            )}

            {!dynamicMode && (
                <div className={`${classPrefix}-nav`}>
                    {!isFirstStep ? (
                        <button
                            type="button"
                            className={`${classPrefix}-nav__prev`}
                            onClick={onPrevious}
                        >
                            <div className={`${classPrefix}-nav__prev-icon`}>
                                <ArrowLeftIcon />
                            </div>
                            <span className={`${classPrefix}-nav__prev-text`}>Previous</span>
                        </button>
                    ) : (
                        <div />
                    )}

                    {wasPreAnswered ? (
                        <button
                            type="button"
                            className={`${classPrefix}-nav__next`}
                            data-disabled={!hasSelection}
                            onClick={handleNextClick}
                            disabled={!hasSelection}
                        >
                            <span className={`${classPrefix}-nav__next-text`}>
                                {isLastStep ? submitButtonText : 'Next'}
                            </span>
                            <div className={`${classPrefix}-nav__next-icon`}>
                                <ArrowRightIcon />
                            </div>
                        </button>
                    ) : (
                        <div />
                    )}
                </div>
            )}
        </div>
    );
}
