/**
 * DOM mounting utilities for Omniguide widgets.
 *
 * Shared by BCProductFitIntegration, BCCategoryGuideIntegration,
 * StencilIntegration, and the ESM loader.
 */

// ── Types ──────────────────────────────────────────────────────────

export type MountPosition = 'before' | 'after' | 'inside' | 'replace';

export interface MountTarget {
  /** CSS selector or HTMLElement to mount relative to */
  target: string | HTMLElement;
  /** Position relative to the target element (default: 'inside') */
  position?: MountPosition;
}

// ── resolveContainer ───────────────────────────────────────────────

/**
 * Resolve or create a container element for mounting a widget.
 *
 * Priority:
 * 1. If `mount` is provided, find/use the target and position a new container relative to it.
 * 2. If `mount` is not provided, fall back to `document.getElementById(defaultId)`.
 *
 * @returns The container HTMLElement to render into, or `null` if the target was not found.
 */
export function resolveContainer(
  mount: MountTarget | undefined,
  defaultId: string,
): HTMLElement | null {
  // Fallback: look for the default container by ID
  if (!mount) {
    return document.getElementById(defaultId);
  }

  // Resolve target element
  const target =
    mount.target instanceof HTMLElement
      ? mount.target
      : document.querySelector<HTMLElement>(mount.target);

  if (!target) {
    return null;
  }

  const position = mount.position ?? 'inside';

  // 'inside' means render directly inside the target (no new container needed)
  if (position === 'inside') {
    return target;
  }

  // 'replace' means swap the target with a new container
  if (position === 'replace') {
    const container = document.createElement('div');
    target.replaceWith(container);
    return container;
  }

  // 'before' or 'after' — create a sibling container
  const container = document.createElement('div');
  if (position === 'before') {
    target.parentNode?.insertBefore(container, target);
  } else {
    // 'after'
    target.parentNode?.insertBefore(container, target.nextSibling);
  }

  return container;
}
