/**
 * Global EventService registry.
 *
 * Allows the bundle to expose `window.Omniguide.trackEvent()` that delegates
 * to whatever EventService instance is currently active (created by
 * OmniguideProvider or manual setup).
 *
 * Theme interceptors call `Omniguide.trackEvent(name, data)` for eCommerce
 * events — this registry routes to the active EventService.
 */

import type { EventService } from './services/events.js';
import type { ConsentService, ConsentState } from './services/consent.js';

let instance: EventService | null = null;
let consentInstance: ConsentService | null = null;

/**
 * Register the active EventService instance.
 * Called by OmniguideProvider when it creates the service.
 */
export function registerEventService(service: EventService): void {
  instance = service;
}

/**
 * Get the registered EventService, or null if none registered yet.
 */
export function getEventService(): EventService | null {
  return instance;
}

/**
 * Track an event via the registered EventService.
 * No-op if no EventService is registered yet.
 *
 * This is the function exposed as `window.Omniguide.trackEvent()`.
 */
export function trackEvent(eventName: string, data: Record<string, unknown> = {}): void {
  if (!instance) return;
  instance.track(eventName, data);
}

/**
 * Update context on the registered EventService.
 * No-op if no EventService is registered yet.
 */
export function updateEventContext(updates: {
  sessionId?: string;
  conversationId?: string;
  messageId?: string;
  websiteId?: string;
}): void {
  if (!instance) return;
  instance.updateContext(updates);
}

/**
 * Register the active ConsentService instance.
 * Called by OmniguideProvider when it creates the service.
 */
export function registerConsentService(service: ConsentService): void {
  consentInstance = service;
}

/**
 * Get the current consent state for debugging.
 * Returns null if no ConsentService is registered yet.
 *
 * Exposed as `window.Omniguide.getConsentState()`.
 */
export function getConsentState(): ConsentState | null {
  if (!consentInstance) return null;
  return consentInstance.getState();
}
