/**
 * Omniguide SDK Debug Logger
 *
 * Provides debug-gated logging for the SDK. Logs are suppressed in production
 * unless explicitly enabled via:
 *
 *   - `localStorage.setItem('ai-debug', 'true')` in the browser console
 *   - Calling `SdkLogger.enable()` programmatically
 *
 * Usage:
 *   import { logger } from './logger.js';
 *   logger.debug('Hydrating products:', products.length);
 *   logger.warn('Unhandled message type:', msg.type);
 *   logger.error('Connection failed:', err);
 *
 * All methods accept the same variadic arguments as console.*.
 * The `warn` and `error` methods always log (even when debug is off),
 * matching standard console severity expectations.
 */

/* eslint-disable no-console */

const STORAGE_KEY = 'ai-debug';
const PREFIX = '[Omniguide]';

type LogFn = (...args: unknown[]) => void;

export interface SdkLogger {
    /** Debug-only log (suppressed unless ai-debug enabled) */
    debug: LogFn;
    /** Always logs — operational warnings */
    warn: LogFn;
    /** Always logs — errors */
    error: LogFn;
    /** Enable debug logging at runtime */
    enable: () => void;
    /** Disable debug logging at runtime */
    disable: () => void;
    /** Check if debug logging is enabled */
    readonly enabled: boolean;
}

let forceEnabled = false;

function isDebugEnabled(): boolean {
    if (forceEnabled) return true;
    try {
        if (typeof localStorage !== 'undefined' && localStorage.getItem(STORAGE_KEY) === 'true') {
            return true;
        }
    } catch {
        // localStorage not available (SSR, private browsing)
    }
    try {
        if (typeof window !== 'undefined') {
            const hostname = window.location?.hostname;
            if (hostname === 'localhost' || hostname === '127.0.0.1') {
                return true;
            }
        }
    } catch {
        // window.location not available
    }
    return false;
}

export const logger: SdkLogger = {
    debug(...args: unknown[]) {
        if (isDebugEnabled()) {
            console.log(PREFIX, ...args);
        }
    },

    warn(...args: unknown[]) {
        console.warn(PREFIX, ...args);
    },

    error(...args: unknown[]) {
        console.error(PREFIX, ...args);
    },

    enable() {
        forceEnabled = true;
        try {
            localStorage.setItem(STORAGE_KEY, 'true');
        } catch {
            // Ignore — forceEnabled flag is sufficient
        }
    },

    disable() {
        forceEnabled = false;
        try {
            localStorage.removeItem(STORAGE_KEY);
        } catch {
            // Ignore
        }
    },

    get enabled() {
        return isDebugEnabled();
    },
};

/**
 * Create a scoped logger with a custom prefix (e.g., for hooks or components).
 *
 *   const log = createScopedLogger('useChatMessageHandler');
 *   log.debug('Session ID synced:', id);
 *   // → [Omniguide:useChatMessageHandler] Session ID synced: abc123
 */
export function createScopedLogger(scope: string): SdkLogger {
    const scopedPrefix = `${PREFIX}:${scope}`;
    return {
        debug(...args: unknown[]) {
            if (isDebugEnabled()) {
                console.log(scopedPrefix, ...args);
            }
        },
        warn(...args: unknown[]) {
            console.warn(scopedPrefix, ...args);
        },
        error(...args: unknown[]) {
            console.error(scopedPrefix, ...args);
        },
        enable: logger.enable,
        disable: logger.disable,
        get enabled() {
            return isDebugEnabled();
        },
    };
}
