/**
 * Convert plain-text bullet lines (• or - at line start) into <ul><li> HTML.
 * Non-bullet text is wrapped in <p> tags. Already-HTML content passes through.
 */
export function formatSeoSummary(html: string): string {
  if (!html) return '';
  // If the content already contains list tags, return as-is
  if (/<[uo]l[\s>]/i.test(html)) return html;

  const lines = html.split(/\n/).map((l) => l.trim()).filter(Boolean);
  const parts: string[] = [];
  let bulletBuffer: string[] = [];

  const flushBullets = () => {
    if (bulletBuffer.length === 0) return;
    parts.push('<ul>' + bulletBuffer.map((b) => `<li>${b}</li>`).join('') + '</ul>');
    bulletBuffer = [];
  };

  for (const line of lines) {
    // Match bullet markers: • (bullet), · (middle dot), – (en-dash), — (em-dash),
    // or - (hyphen, only when followed by whitespace to avoid matching negative numbers).
    // At least one space is required after the marker.
    const bulletMatch = line.match(/^(?:[•·–—]|-(?=\s))\s+(.*)/);
    if (bulletMatch) {
      // Even if the text after the bullet marker is empty, treat it as a bullet item
      bulletBuffer.push(bulletMatch[1] ?? '');
    } else {
      flushBullets();
      // Strip wrapping <p> if backend already added it, then re-wrap.
      // Non-greedy to handle edge cases with multiple tags on one line.
      const inner = line.replace(/^<p>([\s\S]*?)<\/p>$/i, '$1');
      parts.push(`<p>${inner}</p>`);
    }
  }
  flushBullets();

  return parts.join('');
}
