/**
 * useBCSearchChat — BigCommerce chat orchestrator hook.
 *
 * Ported from theme `search/hooks/useWebSocketChat.js`.
 * Resolves the hydration chicken-and-egg: creates state first, then passes
 * setMessages/currentMessageIdRef to useBCChatHydration before composing
 * useChatMessageHandler + useChatConnection.
 */

import { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { useOmniguideContext, useChatMessageHandler, useChatConnection } from '@swiftotter/omniguide-react';
import type { ChatMessage, UseWebSocketChatReturn } from '@swiftotter/omniguide-react';
import { filterEmptyContent, transformSummary, createScopedLogger, getRegistryConversationId, setRegistryConversationId } from '@swiftotter/omniguide-core';

const log = createScopedLogger('useBCSearchChat');
import { useBCChatHydration, type BCChatHydrationAPI } from './useBCChatHydration.js';
import { hydrateProducts, hydrateCategories, type HydrationConfig } from '../services/hydration.js';
import { buildBCHydrationConfig } from './buildHydrationConfig.js';

// ── Types ──────────────────────────────────────────────────────────

export interface UseBCSearchChatOptions {
  /** Override tracking callbacks */
  trackMessageSent?: (data: {
    messageLength: number;
    isFollowUp: boolean;
    turnNumber: number;
  }) => void;
  trackQuestionAnswered?: (data: {
    questionId: unknown;
    questionText: string;
    answer: string;
    context: string;
  }) => void;
  trackRecommendationProvided?: (data: {
    messageId: string;
    recommendationType: string;
    itemCount: number;
    context: string;
  }) => void;
  trackStartOver?: (data: {
    context: string;
    messageCount: number;
  }) => void;
  /** Auto-connect WebSocket on mount (default: true) */
  autoConnect?: boolean;
  /**
   * Reactive session ID from useSessionInit.
   * When provided, used instead of reading localStorage (avoids race condition
   * where localStorage hasn't been populated yet on fresh origins).
   */
  sessionId?: string | null;
}

// ── Helpers ────────────────────────────────────────────────────────

const generateId = () =>
  `msg_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;

// ── Hook ───────────────────────────────────────────────────────────

export function useBCSearchChat({
  trackMessageSent,
  trackQuestionAnswered,
  trackRecommendationProvided,
  trackStartOver,
  autoConnect = true,
  sessionId: externalSessionId,
}: UseBCSearchChatOptions = {}): UseWebSocketChatReturn {
  const { config, platformAdapter } = useOmniguideContext();
  const { websiteId, apiBaseUrl, storageKeys, connectionTimeout } = config;

  const conversationStorageKey = storageKeys?.conversationId ?? 'aiSearchConversationId';
  const sessionStorageKey = storageKeys?.sessionId ?? 'aiSearchSessionId';

  // Pipeline state
  const [pipelineStatus, setPipelineStatus] = useState('idle');

  // Chat state — created first so we can pass to hydration
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [conversationId, setConversationId] = useState<string | null>(() => {
    return getRegistryConversationId(websiteId)
      ?? localStorage.getItem(conversationStorageKey)
      ?? null;
  });
  const [sessionId, setSessionId] = useState<string | null>(() => {
    return localStorage.getItem(sessionStorageKey) ?? null;
  });
  const [error, setError] = useState<string | null>(null);

  // Latency handling (Non-Negotiable #4)
  const [isThinking, setIsThinking] = useState(false);
  const [isTimedOut, setIsTimedOut] = useState(false);

  // Intent/clarification questions
  const [pendingIntentQuestion, setPendingIntentQuestion] = useState<unknown>(null);
  const [pendingClarificationQuestion, setPendingClarificationQuestion] = useState<unknown>(null);

  // Refs
  const currentMessageIdRef = useRef<string | null>(null);
  const conversationIdRef = useRef(conversationId);
  const messagesRef = useRef(messages);
  messagesRef.current = messages;

  // Sync conversation ID with registry, localStorage, and ref
  useEffect(() => {
    conversationIdRef.current = conversationId;
    setRegistryConversationId(websiteId, conversationId);
    if (conversationId) {
      localStorage.setItem(conversationStorageKey, conversationId);
    } else {
      localStorage.removeItem(conversationStorageKey);
    }
  }, [conversationId, conversationStorageKey, websiteId]);

  // Build hydration API from SDK services
  const hydrationConfig = useMemo<HydrationConfig>(
    () => buildBCHydrationConfig(config, platformAdapter),
    [config, platformAdapter],
  );

  const api = useMemo<BCChatHydrationAPI>(() => ({
    fetchProductData: (products) => hydrateProducts(hydrationConfig, products),
    fetchCategoryData: (categories) => hydrateCategories(hydrationConfig, categories),
    fetchContentData: async (content) => {
      if (!content || content.length === 0) return [];
      return filterEmptyContent(
        content.map((article: Record<string, unknown>) => ({
          id: article['id'],
          name: (article['title'] as string) || '',
          url: article['url'],
          summary: article['summary']
            ? transformSummary(article['summary'] as string)
            : '',
          image: { url: article['image'], altText: article['name'] },
        })),
      );
    },
  }), [hydrationConfig]);

  // Initialize hydration hook — passes setMessages + currentMessageIdRef
  const storefrontToken = platformAdapter.getCredentials()['storefrontToken'] ?? '';
  const hydration = useBCChatHydration({
    storefrontToken,
    setMessages,
    currentMessageIdRef,
    trackRecommendationProvided,
    api,
    redundantContentUrls: config.ui?.redundantContentUrls,
  });

  // Initialize message handler
  const { handleMessage, startResponseTimer, resetStreamingState } =
    useChatMessageHandler({
      websiteId,
      setMessages,
      setIsLoading,
      setPipelineStatus,
      setIsThinking,
      setIsTimedOut,
      setError,
      setConversationId,
      setSessionId,
      setPendingIntentQuestion,
      setPendingClarificationQuestion,
      currentMessageIdRef,
      hydration,
      query,
      messages,
      buildFallbackSearchUrl: (q: string) =>
        `/search.php?search_query=${encodeURIComponent(q)}`,
    });

  // Initialize connection hook
  const {
    connectionStatus,
    hasAttemptedConnection,
    reconnectInfo,
    connect,
    disconnect,
    sendQuery,
    resetConnection,
    isConnected,
    setWebSocketConversationId,
  } = useChatConnection({
    websiteId,
    apiBaseUrl,
    sessionId: externalSessionId ?? localStorage.getItem(sessionStorageKey) ?? undefined,
    onMessage: handleMessage,
    conversationIdRef,
    autoConnect,
    connectionTimeout,
  });

  // Sync conversation ID with WebSocket
  useEffect(() => {
    setWebSocketConversationId(conversationId);
  }, [conversationId, setWebSocketConversationId]);

  // Send a message
  const sendMessage = useCallback(
    async (content: string, metadata: Record<string, unknown> = {}) => {
      if (!content?.trim()) return;

      if (!isConnected()) {
        try {
          await connect();
        } catch (err) {
          log.error('Failed to connect WebSocket:', err);
          setError('Unable to connect. Please try again.');
          return;
        }
      }

      // Track message for analytics
      const userMessages = messagesRef.current.filter(
        (m) => m.role === 'user',
      );
      const isFollowUp = userMessages.length > 0;
      const turnNumber = userMessages.length + 1;

      trackMessageSent?.({
        messageLength: content.trim().length,
        isFollowUp,
        turnNumber,
      });

      // Reset streaming state
      resetStreamingState();
      setPendingIntentQuestion(null);
      setPendingClarificationQuestion(null);
      setError(null);
      setIsLoading(true);
      setIsThinking(false);
      setIsTimedOut(false);

      // Start response timer for latency handling
      startResponseTimer();

      // Add user message
      const userMessage: ChatMessage = {
        id: generateId(),
        role: 'user',
        content: content.trim(),
        timestamp: new Date(),
      };

      // Create placeholder for assistant response
      const assistantMessageId = generateId();
      currentMessageIdRef.current = assistantMessageId;

      const assistantMessage: ChatMessage = {
        id: assistantMessageId,
        role: 'assistant',
        content: '',
        timestamp: new Date(),
        isStreaming: true,
        sources: [],
        queryContext: content.trim(),
        suggestions: [],
      };

      setMessages((prev) => [assistantMessage, userMessage, ...prev]);

      // Send query via WebSocket
      try {
        sendQuery(content.trim(), metadata);
      } catch (err) {
        log.error('Failed to send message:', err);
        setError('Failed to send message');
        setIsLoading(false);
        setMessages((prev) =>
          prev.filter((m) => m.id !== assistantMessageId),
        );
      }
    },
    [
      isConnected,
      connect,
      sendQuery,
      trackMessageSent,
      resetStreamingState,
      startResponseTimer,
    ],
  );

  // Send intent question answer
  const sendIntentAnswer = useCallback(
    (
      answerText: string,
      answerId: string,
      options: { isOtherAnswer?: boolean; otherAnswerText?: string } = {},
    ) => {
      const question = pendingIntentQuestion as Record<string, unknown> | null;
      const isDiscoveryQuestion = question?.['_isDiscoveryQuestion'];
      const questionId =
        (question?.['question_id'] as string) ??
        (question?.['id'] as string);

      // Save to shared storage for cross-component persistence
      if (questionId) {
        try {
          const storageKey =
            config.storageKeys?.answeredIntents ?? 'aiAnsweredIntents';
          const raw = localStorage.getItem(storageKey);
          const currentIntents = raw ? JSON.parse(raw) : {};

          if (isDiscoveryQuestion) {
            currentIntents[questionId] = {
              question_id: questionId,
              answer_id: answerId,
              answer_text: answerText,
              is_other: options.isOtherAnswer || false,
              other_text: options.otherAnswerText,
            };
          } else {
            currentIntents[questionId] = {
              answer_id: answerId,
              answer: answerText,
            };
          }

          localStorage.setItem(storageKey, JSON.stringify(currentIntents));
        } catch (e) {
          log.warn('Failed to save answered intent:', e);
        }
      }

      // Track question answered
      if (trackQuestionAnswered && question) {
        trackQuestionAnswered({
          questionId,
          questionText:
            (question['question_text'] as string) ??
            (question['question'] as string) ??
            '',
          answer: answerText,
          context: isDiscoveryQuestion ? 'discovery' : 'intent',
        });
      }

      // Send message with appropriate metadata
      if (isDiscoveryQuestion) {
        const metadata: Record<string, unknown> = {
          discovery_answer_id: answerId,
          discovery_question_id: questionId,
        };

        if (options.isOtherAnswer) {
          metadata['is_other_answer'] = true;
          metadata['other_answer_text'] =
            options.otherAnswerText || answerText;
        }

        sendMessage(answerText, metadata);
      } else {
        sendMessage(answerText, { intent_question_answer_id: answerId });
      }
    },
    [sendMessage, pendingIntentQuestion, trackQuestionAnswered, config.storageKeys],
  );

  // Send clarification question answer
  const sendClarificationAnswer = useCallback(
    (answerText: string, optionId: string, paramName: string) => {
      const question = pendingClarificationQuestion as Record<
        string,
        unknown
      > | null;

      if (trackQuestionAnswered && question) {
        trackQuestionAnswered({
          questionId:
            (question['id'] as string) ?? paramName,
          questionText:
            (question['question_text'] as string) ??
            (question['question'] as string) ??
            '',
          answer: answerText,
          context: 'clarification',
        });
      }

      sendMessage(answerText, { [paramName]: optionId });
    },
    [sendMessage, pendingClarificationQuestion, trackQuestionAnswered],
  );

  // Clear error
  const clearError = useCallback(() => {
    setError(null);
  }, []);

  // Reset chat
  const handleResetChat = useCallback(() => {
    if (trackStartOver) {
      trackStartOver({
        context: window.location.pathname.includes('/products/')
          ? 'product'
          : window.location.pathname.includes('/category/')
            ? 'category'
            : 'search',
        messageCount: messagesRef.current.length,
      });
    }

    setMessages([]);
    setConversationId(null);
    setQuery('');
    setPendingIntentQuestion(null);
    setPendingClarificationQuestion(null);
    setError(null);
    currentMessageIdRef.current = null;
    resetStreamingState();
    resetConnection();
  }, [trackStartOver, resetStreamingState, resetConnection]);

  return {
    // Connection state
    connectionStatus,
    hasAttemptedConnection,
    reconnectInfo,
    pipelineStatus,
    isConnected: connectionStatus === 'connected',

    // Chat state
    messages,
    query,
    setQuery,
    isLoading,
    conversationId,
    sessionId,
    error,

    // Latency states (Non-Negotiable #4)
    isThinking,
    isTimedOut,

    // Intent questions
    pendingIntentQuestion,

    // Clarification questions
    pendingClarificationQuestion,

    // Actions
    connect,
    disconnect,
    sendMessage,
    sendIntentAnswer,
    sendClarificationAnswer,
    handleResetChat,
    clearError,

    // Compatibility
    fetchResults: sendMessage,
  };
}
