/**
 * Fetch real product URLs from a BigCommerce backend by SKUs.
 * Used by the search chat to resolve product links in streamed markdown.
 *
 * Routes through `fetchDataByIds` so concurrent calls for the same SKUs share the
 * in-flight request cache with `hydrateProducts` (same endpoint, same response shape).
 */

import { createScopedLogger, API_ENDPOINTS } from '@swiftotter/omniguide-core';
import { fetchDataByIds, type HydrationConfig } from './hydration.js';
import { fetchProductsDirectGraphQL } from './directGraphQL.js';

const log = createScopedLogger('productUrls');

export type ProductUrlsConfig = HydrationConfig;

export async function fetchProductUrlsBySkus(
    skus: string[],
    config: ProductUrlsConfig,
): Promise<Record<string, string>> {
    if (!skus || skus.length === 0) return {};

    const endpoint = config.productHydrationEndpoint
        ? `/api/v1${config.productHydrationEndpoint}`
        : API_ENDPOINTS.BC_SEARCH_PRODUCTS;

    const products = await fetchDataByIds<Record<string, unknown>>(
        config,
        skus,
        endpoint,
        'skus',
        'products',
        (ids, options) =>
            fetchProductsDirectGraphQL(ids.map(String), options) as Promise<Record<string, unknown>[]>,
    );

    const urlMap: Record<string, string> = {};
    products.forEach((product) => {
        const productUrl =
            (product['url'] as string) ??
            (product['path'] as string) ??
            (product['custom_url'] as Record<string, string> | undefined)?.['url'];

        if (product['sku'] && productUrl) {
            urlMap[String(product['sku'])] = productUrl;
        }
    });

    const missingSkus = skus.filter((sku) => !urlMap[String(sku)]);
    if (missingSkus.length > 0) {
        log.warn('Product URLs not found for SKUs:', missingSkus);
    }

    return urlMap;
}
