import React, { memo, useRef } from 'react';
import { buildSafeUrl, safeNavigate, decodeHtmlEntities } from '../../utils/index.js';
import { ReviewInsightsToggle, ProductTag } from '../discovery/index.js';

export interface SearchProductData {
    display_name?: string;
    name?: string;
    product_line?: string;
    brand?: { name?: string } | string;
    url?: string;
    path?: string;
    sku?: string;
    entityId?: number | string;
    id?: number | string;
    imageUrl?: string;
    price?: number | string;
    originalPrice?: number | string;
    tag?: { type: string; label?: string };
    review_insights?: {
        average_rating?: number;
        review_count?: number;
        summary?: string;
        likes?: string[];
    };
    rating?: number;
}

export interface SearchProductCardProps {
    product: SearchProductData | null;
    index: number;
    messageId?: string;
    queryContext?: string;
    trackProductClick?: (data: Record<string, unknown>) => void;
    aiSearchStoreUrl?: string;
    fallbackImage?: string;
    showProductTags?: boolean;
    /** How to display zero/null price: 'show' (default) | 'hide' | custom text */
    zeroPriceDisplay?: string;
}

/** Check if product has a zero/null/undefined price */
function isZeroPrice(price: number | string | undefined | null): boolean {
    return price === 0 || price === '0' || price === '$0' || price == null;
}

export const SearchProductCard: React.FC<SearchProductCardProps> = memo(({
    product,
    index,
    messageId,
    queryContext,
    trackProductClick,
    aiSearchStoreUrl,
    fallbackImage,
    showProductTags = true,
    zeroPriceDisplay = 'show',
}) => {
    const redirectTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    if (!product) return null;

    // Hide entire card if configured and price is zero
    if (zeroPriceDisplay === 'hide' && isZeroPrice(product.price)) return null;

    const displayName = product.name || product.display_name || '';
    const rawBrand = product.product_line ||
        (typeof product.brand === 'object' ? product.brand?.name : product.brand) || '';
    const brandName = rawBrand;
    // Strip brand prefix from display name to avoid visual duplication (brand shown on its own line)
    const cleanDisplayName = (rawBrand && displayName.toLowerCase().startsWith(rawBrand.toLowerCase() + ' '))
        ? displayName.slice(rawBrand.length).trimStart() || displayName
        : displayName;

    const handleClick = (event: React.MouseEvent | React.KeyboardEvent) => {
        const urlPath = product.url || product.path;

        if (!urlPath) return;

        const safeUrl = buildSafeUrl(aiSearchStoreUrl, urlPath);
        if (!safeUrl) return;

        if (trackProductClick) {
            trackProductClick({
                messageId,
                productId: product.entityId || product.id,
                productSku: product.sku,
                position: index,
                queryContext,
            });
        }

        redirectTimerRef.current = setTimeout(() => {
            safeNavigate(safeUrl, undefined, { event: event as unknown as { ctrlKey?: boolean; metaKey?: boolean } });
        }, 0);
    };

    const discount = product.originalPrice && product.price
        ? Math.round((1 - Number(product.price) / Number(product.originalPrice)) * 100)
        : null;

    const getModifierClass = () => {
        if (!showProductTags || !product.tag?.type) return '';
        const tagType = product.tag.type.toLowerCase().replace(/[_\s]/g, '-');
        if (tagType === 'recommended') return 'omniguide-product-card--top-pick';
        if (tagType === 'runner-up' || tagType === 'runnerup') return 'omniguide-product-card--runner-up';
        if (tagType === 'bad-fit' || tagType === 'badfit') return 'omniguide-product-card--bad-fit';
        return '';
    };

    const formatPrice = (price: number | string) => {
        if (typeof price === 'number') {
            return `$${price.toLocaleString()}`;
        }
        if (typeof price === 'string' && !price.startsWith('$')) {
            return `$${price}`;
        }
        return price;
    };

    // Determine if we should show custom text for zero price
    const hasZeroPrice = isZeroPrice(product.price);
    const showCustomZeroPriceText = hasZeroPrice && zeroPriceDisplay !== 'show';

    const cardClassName = `omniguide-product-card ${getModifierClass()}`.trim();

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            handleClick(e);
        }
    };

    return (
        <div
            className={cardClassName}
            onClick={handleClick}
            onKeyDown={handleKeyDown}
            tabIndex={0}
            role="link"
            aria-label={`View ${decodeHtmlEntities(cleanDisplayName)}${brandName ? ` by ${decodeHtmlEntities(brandName)}` : ''}`}
            data-product-card
        >
            <div className="omniguide-product-card__image-wrapper">
                <img
                    src={product.imageUrl || fallbackImage || ''}
                    alt={decodeHtmlEntities(cleanDisplayName)}
                    className="omniguide-product-card__image"
                />

                {discount != null && discount > 0 && (
                    <div className="omniguide-product-card__discount-badge">
                        -{discount}%
                    </div>
                )}

                {showProductTags && !discount && product.tag && <ProductTag tag={product.tag} classPrefix="omniguide-ai-tag" />}
            </div>

            <div className="omniguide-product-card__body">
                <div className="omniguide-product-card__title-group">
                    {brandName && (
                        <p className="omniguide-product-card__brand">
                            {decodeHtmlEntities(brandName)}
                        </p>
                    )}
                    <h4 className="omniguide-product-card__title">
                        {decodeHtmlEntities(cleanDisplayName)}
                    </h4>
                </div>

                <div className="omniguide-product-card__price-rating-row">
                    <div className="omniguide-product-card__price-group">
                        {showCustomZeroPriceText ? (
                            <span className="omniguide-product-card__price omniguide-product-card__price--call">
                                {zeroPriceDisplay}
                            </span>
                        ) : (
                            <>
                                {product.price != null && (
                                    <span className="omniguide-product-card__price">
                                        {formatPrice(product.price)}
                                    </span>
                                )}
                                {product.originalPrice && product.originalPrice !== product.price && (
                                    <span className="omniguide-product-card__price omniguide-product-card__price--original">
                                        {formatPrice(product.originalPrice)}
                                    </span>
                                )}
                            </>
                        )}
                    </div>
                    {(product.review_insights?.average_rating != null && product.review_insights.average_rating > 0 || product.rating) && (
                        <ReviewInsightsToggle
                            rating={product.review_insights?.average_rating || product.rating || 0}
                            reviewCount={product.review_insights?.review_count || 0}
                            summary={product.review_insights?.summary}
                            likes={product.review_insights?.likes}
                        />
                    )}
                </div>
            </div>
        </div>
    );
});

SearchProductCard.displayName = 'SearchProductCard';
