import React, { memo } from 'react';

export interface BenefitsListProps {
    benefits?: string[];
    maxItems?: number;
    showTitle?: boolean;
    classPrefix?: string;
}

const CheckIcon = () => (
    <svg
        className="omniguide-cr-benefits__icon"
        viewBox="0 0 20 20"
        fill="currentColor"
    >
        <path
            fillRule="evenodd"
            d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"
            clipRule="evenodd"
        />
    </svg>
);

export const BenefitsList = memo(function BenefitsList({
    benefits = [],
    maxItems = 4,
    showTitle = true,
    classPrefix = 'omniguide-cr',
}: BenefitsListProps): JSX.Element | null {
    if (!benefits || benefits.length === 0) {
        return null;
    }

    const displayedBenefits = benefits.slice(0, maxItems);

    return (
        <div>
            {showTitle && <h4 className={`${classPrefix}-benefits__title`}>BENEFITS</h4>}
            <ul className={`${classPrefix}-benefits__list`}>
                {displayedBenefits.map((benefit) => (
                    <li key={benefit} className={`${classPrefix}-benefits__item`}>
                        <CheckIcon />
                        <span>{benefit}</span>
                    </li>
                ))}
            </ul>
        </div>
    );
});
