/**
 * Auto-init — creates integration instances for enabled features.
 */

import type { OmniguideConfig, PlatformAdapter, OmniguideFeatures, SearchIntegration, FeatureIntegration } from '@swiftotter/omniguide-core';
import { logger } from '@swiftotter/omniguide-core';
import {
  BCSearchIntegration,
  BCProductFitIntegration,
  BCCategoryGuideIntegration,
} from '@swiftotter/omniguide-bigcommerce';

import type { BundleInitConfig, OmniguideInstance } from './types.js';
import { setupSearchTrigger, type SearchTriggerResult } from './search-trigger.js';

/**
 * Create and initialize integration instances for all enabled features.
 */
export function autoInit(
  config: OmniguideConfig,
  platformAdapter: PlatformAdapter,
  features: OmniguideFeatures,
  searchOptions?: BundleInitConfig['search'],
  pdpWidget?: BundleInitConfig['pdpWidget'],
  plpWidget?: BundleInitConfig['plpWidget'],
): OmniguideInstance {
  let search: SearchIntegration | null = null;
  let productFit: FeatureIntegration | null = null;
  let categoryGuide: FeatureIntegration | null = null;
  let triggerResult: SearchTriggerResult | null = null;

  const integrationConfig = { config, platformAdapter };

  if (features.search) {
    try {
      const hasTrigger = !!searchOptions?.trigger;
      const hasReplace = searchOptions?.replace !== undefined;
      const hasRenderTrigger = !!searchOptions?.renderTrigger;
      const hasCustomTrigger = hasTrigger || hasReplace || hasRenderTrigger;

      if (hasCustomTrigger && searchOptions?.replace !== null) {
        // Custom trigger mode: skipDomSetup, let search-trigger.ts or simple click binding handle the trigger
        search = new BCSearchIntegration({ ...integrationConfig, skipDomSetup: true });
        search.init();

        if (hasTrigger && !hasReplace && !hasRenderTrigger) {
          // Simplest path: just bind click to existing element(s)
          const triggerListeners: Array<{ el: Element; handler: EventListener }> = [];
          const openFn = (query: string, source: string) => search!.openSearch(query, source);
          document.querySelectorAll(searchOptions!.trigger!).forEach((el) => {
            const handler = ((e: Event) => {
              e.preventDefault();
              openFn('', 'trigger_click');
            }) as EventListener;
            // Use bubble phase (false) to avoid intercepting clicks before analytics handlers
            el.addEventListener('click', handler, false);
            triggerListeners.push({ el, handler });
          });
          triggerResult = {
            openSearch: (query?: string, source?: string) => openFn(query ?? '', source ?? 'programmatic'),
            addIntentListeners: () => () => {},
            destroy: () => {
              for (const { el, handler } of triggerListeners) {
                el.removeEventListener('click', handler, false);
              }
            },
          };
        } else {
          // search-trigger.ts handles replace / renderTrigger / icon
          triggerResult = setupSearchTrigger({
            replace: searchOptions?.replace ?? undefined,
            renderTrigger: searchOptions?.renderTrigger,
            icon: searchOptions?.icon,
            selectors: config.selectors,
            websiteId: config.websiteId,
          }, (query, source) => search!.openSearch(query, source));
        }
      } else if (searchOptions?.replace === null) {
        // Manual mode: no trigger, no BC overrides — user calls openSearch() manually
        search = new BCSearchIntegration({ ...integrationConfig, skipDomSetup: true });
        search.init();
      } else {
        // No search options provided — platform-specific defaults
        search = new BCSearchIntegration(integrationConfig);
        search.init();
      }
    } catch (e) {
      logger.error('Failed to init search:', e);
      search = null;
    }
  }

  if (features.productFit) {
    try {
      productFit = new BCProductFitIntegration({ ...integrationConfig, mount: pdpWidget?.mount });
      productFit.init();
    } catch (e) {
      logger.error('Failed to init product fit:', e);
      productFit = null;
    }
  }

  if (features.categoryGuide) {
    try {
      logger.debug('CategoryGuide: init starting, mount =', plpWidget?.mount ?? '(none)');
      categoryGuide = new BCCategoryGuideIntegration({ ...integrationConfig, mount: plpWidget?.mount });
      const result = categoryGuide.init();
      logger.debug('CategoryGuide: init result =', result);
    } catch (e) {
      logger.error('Failed to init category guide:', e);
      categoryGuide = null;
    }
  }

  return {
    search,
    productFit,
    categoryGuide,
    openSearch: (query?: string) => search?.openSearch(query ?? '', 'programmatic'),
    destroy() {
      triggerResult?.destroy();
      search?.destroy();
      productFit?.destroy();
      categoryGuide?.destroy();
    },
  };
}
