/**
 * Format a price value into a display string with currency symbol.
 *
 * Handles both number and string inputs. Strips dollar signs from strings.
 * Omits trailing ".00" for whole dollar amounts.
 *
 * @returns Formatted string like "$29" or "$29.99", or null if value is falsy.
 */
export function formatPrice(value: number | string | null | undefined): string | null {
    if (value === null || value === undefined || value === '') return null;

    let numericPrice: number;
    if (typeof value === 'number') {
        numericPrice = value;
    } else if (typeof value === 'string') {
        numericPrice = parseFloat(value.replace('$', ''));
    } else {
        return null;
    }

    if (Number.isNaN(numericPrice)) return null;

    if (Number.isInteger(numericPrice)) {
        return `$${numericPrice}`;
    }
    return `$${numericPrice.toFixed(2)}`;
}
