/**
 * Response latency thresholds (Non-Negotiable #4)
 *
 * THINKING_THRESHOLD: Show "Thinking..." UI after this delay (3s)
 * RESPONSE_TIMEOUT: Hard timeout with retry option (10s)
 */
export const LATENCY = {
  THINKING_THRESHOLD: 3000,
  RESPONSE_TIMEOUT: 10000,
} as const;

/**
 * Default reconnection settings
 */
export const RECONNECTION = {
  MAX_ATTEMPTS: 5,
  BASE_DELAY: 1000,
  MAX_BACKOFF_DELAY: 30000,
} as const;

/**
 * Flow states for conversational discovery questionnaires.
 * Shared state machine for both category and product questionnaire flows.
 */
export const FLOW_STATES = {
  IDLE: 'idle',
  LOADING_FIRST: 'loading_first',
  SHOWING_FIRST: 'showing_first',
  CONNECTING: 'connecting',
  QUESTIONING: 'questioning',
  LOADING_RESULTS: 'loading_results',
  COMPLETE: 'complete',
  ERROR: 'error',
} as const;

export type FlowState = typeof FLOW_STATES[keyof typeof FLOW_STATES];

/**
 * Detect if running on localhost
 */
export function isLocalhost(): boolean {
  if (typeof window === 'undefined') return false;
  return window.location.origin.includes('localhost');
}

/**
 * Get the appropriate Omniguide backend URL.
 * Priority: localStorage preview override > customUrl > localhost detection > production
 */
export function getApiBaseUrl(customUrl?: string): string {
  const previewUrl = getPreviewApiUrl();
  if (previewUrl) return previewUrl;
  if (customUrl) return customUrl;
  return isLocalhost() ? API_URLS.LOCAL : API_URLS.PRODUCTION;
}
