/**
 * Consent Service
 *
 * Manages user consent preferences using a two-tier model:
 * 1. Website consent — read-only from cookie (e.g. BigCommerce tracking-preferences)
 * 2. Omniguide consent — read/write from localStorage
 *
 * Effective consent = websiteConsent && omniguideConsent.
 * Omniguide NEVER writes to the website's consent cookie.
 */

import { API_ENDPOINTS } from '../constants.js';
import { createScopedLogger } from '../logger.js';

const log = createScopedLogger('ConsentService');

// =========================================
// Types
// =========================================

export interface ConsentScopes {
  analytics: boolean;
  advertising: boolean;
}

export interface ConsentState {
  initialized: boolean;
  analytics: boolean;       // effective: website && omniguide
  advertising: boolean;     // effective: website && omniguide
  websiteConsent: boolean;  // read-only from website cookie
  omniguideConsent: boolean; // user's Omniguide preference (localStorage)
}

export interface ConsentServiceConfig {
  /** Omniguide backend base URL */
  apiBaseUrl: string;
  /**
   * Custom function to read consent scopes from the page.
   * Defaults to reading the `tracking-preferences` cookie
   * with the BigCommerce/Segment format.
   */
  getConsentScopes?: () => ConsentScopes;
  /**
   * Cookie name to read consent from (only used by default reader).
   * Defaults to 'tracking-preferences'.
   */
  cookieName?: string;
}

// =========================================
// Default Cookie Reader (read-only)
// =========================================

function readCookie(name: string): string | null {
  if (typeof document === 'undefined') return null;

  const entry = document.cookie
    .split('; ')
    .find((row) => row.startsWith(name + '='));

  if (!entry) return null;
  const eqIndex = entry.indexOf('=');
  return eqIndex === -1 ? null : entry.substring(eqIndex + 1);
}

function defaultGetConsentScopes(cookieName: string): ConsentScopes {
  try {
    const raw = readCookie(cookieName);
    if (!raw) {
      return { analytics: false, advertising: false };
    }

    const decoded = decodeURIComponent(raw);
    const parsed = JSON.parse(decoded);
    const custom = (parsed && parsed.custom) || {};

    return {
      analytics: !!custom.marketingAndAnalytics,
      advertising: !!custom.advertising,
    };
  } catch {
    return { analytics: false, advertising: false };
  }
}

// Shared in-memory omniguide consent — all ConsentService instances read/write
// this single value so toggles sync across separate React trees (search, PDP, PLP).
// Resets to true on every page load (no storage persistence).
let sharedOmniguideConsent = true;

/** @internal Reset shared consent state (for testing only). */
export function _resetSharedOmniguideConsent(): void {
  sharedOmniguideConsent = true;
}

// =========================================
// ConsentService
// =========================================

export class ConsentService {
  private apiBaseUrl: string;
  private cookieName: string;
  private getConsentScopes: () => ConsentScopes;

  private initialized = false;
  private _websiteConsent = false;
  private lastScopeJson: string | null = null;
  private lastCanSendAnalytics: boolean | null = null;

  private watcherStarted = false;
  private watcherIntervalId: ReturnType<typeof setInterval> | null = null;

  constructor(config: ConsentServiceConfig) {
    this.apiBaseUrl = config.apiBaseUrl.replace(/\/$/, '');
    this.cookieName = config.cookieName ?? 'tracking-preferences';
    this.getConsentScopes =
      config.getConsentScopes ??
      (() => defaultGetConsentScopes(this.cookieName));

    // Eagerly read tiers so UI has correct websiteConsent before ensureInitialized()
    this.readTiers();
  }

  /** Compute effective consent scopes from the two-tier model. */
  private getEffectiveScopes(): ConsentScopes {
    const effective = this._websiteConsent && sharedOmniguideConsent;
    return { analytics: effective, advertising: effective };
  }

  private dispatchChange(): void {
    if (typeof window !== 'undefined') {
      window.dispatchEvent(new CustomEvent('consent-state-changed'));
    }
  }

  private async sendScopeToServer(sessionId: string, scope: ConsentScopes): Promise<boolean> {
    const url = `${this.apiBaseUrl}${API_ENDPOINTS.CONSENT}`;

    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        session_id: sessionId,
        scope,
      }),
    });

    return res.ok;
  }

  /** Read website consent from cookie. Omniguide consent is in-memory only. */
  private readTiers(): void {
    const websiteScopes = this.getConsentScopes();
    this._websiteConsent = websiteScopes.analytics || websiteScopes.advertising;
    // _omniguideConsent stays at its current in-memory value (default: true)
  }

  /**
   * Initialize consent by reading website cookie + localStorage, then sync with server.
   * No-op if already initialized or no sessionId.
   */
  async ensureInitialized(sessionId: string): Promise<void> {
    if (this.initialized || !sessionId) return;

    this.readTiers();
    const scope = this.getEffectiveScopes();
    this.lastScopeJson = JSON.stringify(scope);

    try {
      const ok = await this.sendScopeToServer(sessionId, scope);
      if (!ok) {
        // Server error — log but keep cookie-derived consent.
        // The server call notifies the backend; it does NOT determine consent.
        log.warn('Consent server returned non-200 — keeping cookie-derived consent');
      }
    } catch (e) {
      // Network error — log but keep cookie-derived consent.
      log.warn('Consent server unreachable — keeping cookie-derived consent:', e);
    }

    this.initialized = true;
    this.dispatchChange();
  }

  /**
   * Re-read consent from cookie + localStorage and sync with server if changed.
   */
  async refresh(sessionId: string): Promise<void> {
    if (!sessionId) return;

    this.readTiers();
    const scope = this.getEffectiveScopes();
    const scopeJson = JSON.stringify(scope);

    // Only sync if changed
    if (scopeJson !== this.lastScopeJson) {
      this.lastScopeJson = scopeJson;
      try {
        const ok = await this.sendScopeToServer(sessionId, scope);
        if (!ok) {
          log.warn('Consent refresh server returned non-200 — keeping cookie-derived consent');
        }
      } catch (e) {
        log.warn('Consent refresh server unreachable — keeping cookie-derived consent:', e);
      }
    }

    this.initialized = true;
    this.dispatchChange();
  }

  /**
   * Start periodic consent watcher that detects website cookie changes.
   */
  startWatcher(sessionId: string, intervalMs: number = 3600000): void {
    if (this.watcherStarted || !sessionId) return;

    this.watcherStarted = true;

    this.watcherIntervalId = setInterval(async () => {
      await this.refresh(sessionId);
    }, intervalMs);
  }

  /**
   * Stop the periodic consent watcher.
   */
  stopWatcher(): void {
    if (this.watcherIntervalId) {
      clearInterval(this.watcherIntervalId);
      this.watcherIntervalId = null;
    }
    this.watcherStarted = false;
  }

  /**
   * Whether analytics events can be sent (effective consent).
   *
   * Consent comes from cookie + localStorage, both read synchronously in the
   * constructor via readTiers(). `initialized` only indicates that the consent
   * state has been synced to the server — it is NOT a precondition for sending
   * events. Gating on it caused click-driven events to drop when each
   * integration's ConsentService server-sync was still in flight at click time
   * (one ConsentService instance per OmniguideProvider).
   */
  canSendAnalytics(): boolean {
    const can = this._websiteConsent && sharedOmniguideConsent;
    // Log only on state transition to avoid spam from periodic flush checks
    if (can !== this.lastCanSendAnalytics) {
      this.lastCanSendAnalytics = can;
      if (!can) {
        log.debug(`canSendAnalytics=false (websiteConsent=${this._websiteConsent}, omniguideConsent=${sharedOmniguideConsent})`);
      }
    }
    return can;
  }

  /**
   * Whether advertising events can be sent (effective consent).
   */
  canSendAdvertising(): boolean {
    return this._websiteConsent && sharedOmniguideConsent;
  }

  /**
   * Re-read consent tiers into memory (no server call).
   */
  syncFromCookie(): void {
    this.readTiers();
  }

  /**
   * Get current consent state.
   */
  getState(): ConsentState {
    const effective = this._websiteConsent && sharedOmniguideConsent;
    return {
      initialized: this.initialized,
      analytics: effective,
      advertising: effective,
      websiteConsent: this._websiteConsent,
      omniguideConsent: sharedOmniguideConsent,
    };
  }

  /**
   * Update the Omniguide consent preference.
   * Updates in-memory state — NEVER touches the website cookie or any storage.
   */
  async updatePreferences(sessionId: string, enabled: boolean): Promise<void> {
    sharedOmniguideConsent = enabled;

    this.initialized = true;
    this.dispatchChange();

    // Sync effective state with server
    if (sessionId) {
      const scope = this.getEffectiveScopes();
      this.lastScopeJson = JSON.stringify(scope);
      try {
        await this.sendScopeToServer(sessionId, scope);
      } catch {
        // Intentionally swallowed — user's toggle choice is preserved
      }
    }
  }
}

/**
 * Create a ConsentService instance.
 */
export function createConsentService(config: ConsentServiceConfig): ConsentService {
  return new ConsentService(config);
}
