/**
 * BCCategoryGuideIntegration — DOM integration for category guide in BigCommerce themes.
 *
 * Ported from theme `category-recommendations/index.js`.
 * Mounts BCCategoryGuideContainer in #category-recommendations-root.
 */

import React from 'react';
import { createRoot, type Root } from 'react-dom/client';
import { OmniguideProvider, type OmniguideProviderProps } from '@swiftotter/omniguide-react';
import type { OmniguideComponentOverrides } from '@swiftotter/omniguide-react';
import { resolveContainer, type OmniguideConfig, type PlatformAdapter, type StorageAdapter, type FeatureIntegration, type MountTarget } from '@swiftotter/omniguide-core';
import { watchFeatureStatus } from './featureStatusWatcher.js';
import { BCCategoryGuideContainer } from '../containers/BCCategoryGuideContainer.js';

// ── Types ──────────────────────────────────────────────────────────

export interface BCCategoryGuideIntegrationConfig {
  config: OmniguideConfig;
  platformAdapter: PlatformAdapter;
  storageAdapter?: StorageAdapter;
  /** Custom container component (replaces BCCategoryGuideContainer entirely) */
   
  ContainerComponent?: React.ComponentType<any>;
  /** Sub-component overrides passed to OmniguideProvider */
  components?: OmniguideComponentOverrides;
  /**
   * Mount target for positioning the widget relative to an existing DOM element.
   * When provided, resolveContainer() creates a container at the specified position.
   * Falls back to `document.getElementById('category-recommendations-root')` when not set.
   */
  mount?: MountTarget;
}

// ── Data attribute for preventing double-mount ──────────────────────

const MOUNTED_ATTR = 'data-omniguide-mounted';

// ── Helper ─────────────────────────────────────────────────────────

function adjustContainerHeight(container: HTMLElement): void {
  requestAnimationFrame(() => {
    const content = container.firstElementChild as HTMLElement | null;
    if (content) {
      const contentHeight = content.offsetHeight;
      container.style.minHeight = `${contentHeight}px`;
      setTimeout(() => {
        container.style.minHeight = 'auto';
      }, 300);
    }
  });
}

// ── Class ──────────────────────────────────────────────────────────

export class BCCategoryGuideIntegration implements FeatureIntegration {
  private root: Root | null = null;
  private mountedContainer: HTMLElement | null = null;
  private unsubscribeFeatureStatus?: () => void;
  initialized = false;

  private omniguideConfig: OmniguideConfig;
  private platformAdapter: PlatformAdapter;
  private storageAdapter?: StorageAdapter;
   
  private containerComponent?: React.ComponentType<any>;
  private components?: OmniguideComponentOverrides;
  private mount?: MountTarget;

  constructor({ config, platformAdapter, storageAdapter, ContainerComponent, components, mount }: BCCategoryGuideIntegrationConfig) {
    this.omniguideConfig = config;
    this.platformAdapter = platformAdapter;
    this.storageAdapter = storageAdapter;
    this.containerComponent = ContainerComponent;
    this.components = components;
    this.mount = mount;
  }

  init(): boolean {
    const container = resolveContainer(this.mount, 'category-recommendations-root');
    if (!container) {
      // eslint-disable-next-line no-console -- mount-failure diagnostic at integration boundary
      console.warn('[Omniguide] CategoryGuide: resolveContainer returned null. mount =', this.mount, 'defaultId = category-recommendations-root');
      return false;
    }
    // eslint-disable-next-line no-console -- mount-success diagnostic at integration boundary
    console.log('[Omniguide] CategoryGuide: container found =', container.tagName, container.id || container.className);

    // Hide the DOM container when AI is disabled (prevents empty min-height placeholder)
    this.unsubscribeFeatureStatus?.();
    const watcher = watchFeatureStatus(this.omniguideConfig.websiteId, container);
    this.unsubscribeFeatureStatus = watcher.unsubscribe;

    if (this.root && this.mountedContainer && this.mountedContainer === container && document.body.contains(this.mountedContainer)) {
      this.initialized = true;
      return true;
    }

    if (this.root && this.mountedContainer !== container) {
      try { this.root.unmount(); } catch { /* ignore */ }
      this.mountedContainer?.removeAttribute(MOUNTED_ATTR);
      this.root = null;
      this.mountedContainer = null;
    }

    this.mountComponent(container);
    this.initialized = true;
    return true;
  }

  private mountComponent(container: HTMLElement): void {
    if (container.hasAttribute(MOUNTED_ATTR)) return;

    container.setAttribute(MOUNTED_ATTR, 'true');
    this.root = createRoot(container);
    this.mountedContainer = container;

    const Container = this.containerComponent ?? BCCategoryGuideContainer;
    const providerProps: OmniguideProviderProps = {
      config: this.omniguideConfig,
      platformAdapter: this.platformAdapter,
      storageAdapter: this.storageAdapter,
      components: this.components,
      children: <Container />,
    };

    this.root.render(<OmniguideProvider {...providerProps} />);
    setTimeout(() => adjustContainerHeight(container), 100);
  }

  destroy(): void {
    this.unsubscribeFeatureStatus?.();
    this.unsubscribeFeatureStatus = undefined;
    if (this.root) {
      this.root.unmount();
      this.mountedContainer?.removeAttribute(MOUNTED_ATTR);
      this.mountedContainer = null;
      this.root = null;
    }
  }
}
