/**
 * Markdown → HTML parser with product shortcode support and DOMPurify sanitization.
 *
 * DOM-dependent — belongs in omniguide-react (not omniguide-core).
 */

import DOMPurify from 'dompurify';

export interface ParseMarkdownOptions {
    /** Color for rendered links (default: '#FF4C00') */
    linkColor?: string;
    /** Whether to sanitize output with DOMPurify (default: true) */
    sanitize?: boolean;
    /** Map of SKU → product URL for shortcode resolution */
    productUrls?: Record<string, string>;
    /** Map of SKU → display name for shortcode resolution */
    productNames?: Record<string, string>;
    /** If true, render SKU links as non-clickable text when no verified URL found */
    requireCorrectUrls?: boolean;
}

const DEFAULT_LINK_COLOR = '#FF4C00';

// data-omniguide-sku is consumed by click handlers for backend attribution.
// SKU values come from regex captures over LLM-generated text (or caller maps),
// so emit the attribute only for plausible SKU shapes — cheap hardening that
// holds even for sanitize:false callers, independent of DOMPurify.
const SAFE_SKU_PATTERN = /^[\w.-]+$/;
function skuAttr(sku: string | undefined): string {
    return sku && SAFE_SKU_PATTERN.test(sku) ? ` data-omniguide-sku="${sku}"` : '';
}

/**
 * Parse markdown content into sanitized HTML.
 *
 * Supports:
 * - Standard markdown: bold, italic, inline code, links, lists, paragraphs
 * - Product shortcodes: `[product sku="123"]Name[/product]`, `[Name](sku="123")`, `[Name SKU: 123]`
 * - SKU links in markdown: `[Product Name (SKU: 123)](url)`
 *
 * Note: list handling is LLM-friendly and deviates from strict markdown — an adjacent
 * list of a different type (e.g. bullets immediately after numbered items, no indent)
 * is rendered as a sub-list of the previous item rather than a sibling list, so LLM
 * output with interleaved sub-points keeps numbering continuous.
 */
export function parseMarkdown(content: string, options: ParseMarkdownOptions = {}): string {
    if (!content) return content;

    const linkColor = options.linkColor ?? DEFAULT_LINK_COLOR;
    const shouldSanitize = options.sanitize !== false;
    const productUrls = options.productUrls ?? {};
    const productNames = options.productNames ?? {};
    const requireCorrectUrls = options.requireCorrectUrls ?? false;

    // Reverse map for back-deriving SKU from a plain markdown link URL.
    // When two SKUs share one URL (variant → parent-URL catalogs) the mapping is
    // ambiguous — attribute nothing rather than the wrong SKU.
    const skuByUrl: Record<string, string> = {};
    const ambiguousUrls = new Set<string>();
    for (const [sku, url] of Object.entries(productUrls)) {
        if (!url) continue;
        if (ambiguousUrls.has(url)) continue;
        if (url in skuByUrl) {
            delete skuByUrl[url];
            ambiguousUrls.add(url);
            continue;
        }
        skuByUrl[url] = String(sku);
    }

    let result = content;

    // FORMAT 0 (FIRST): Handle any markdown link [text](url) where text contains (SKU: XX) or SKU: XX
    result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (match: string, linkText: string, originalUrl: string) => {
        if (originalUrl.startsWith('sku=')) {
            return match;
        }

        const skuMatch = linkText.match(/\(SKU:\s*(\d+)\)|SKU:\s*(\d+)/i);

        if (skuMatch) {
            const sku = skuMatch[1] ?? skuMatch[2] ?? '';
            const correctUrl = productUrls[String(sku)] ?? productUrls[sku];
            const cleanName = linkText.replace(/\s*\(SKU:\s*\d+\)/i, '').replace(/\s*SKU:\s*\d+/i, '').trim();
            const displayName = productNames[String(sku)] ?? productNames[sku] ?? cleanName;
            const linkStyle = `color: ${linkColor}; text-decoration: underline; font-weight: 500; cursor: pointer;`;

            const finalUrl = correctUrl ?? originalUrl;

            if (requireCorrectUrls && !correctUrl) {
                const pendingStyle = `color: ${linkColor}; font-weight: 500; opacity: 0.7;`;
                return `<span style="${pendingStyle}">${displayName}</span>`;
            }

            return `<a href="${finalUrl}"${skuAttr(sku)} style="${linkStyle}">${displayName}</a>`;
        }

        return match;
    });

    // Product shortcode format 1: [product sku="SKU"]Product Name[/product]
    result = result.replace(/\[product\s+sku=['"]([^'"]+)['"]\]([^[]+)\[\/product\]/g, (_match: string, sku: string, productName: string) => {
        const productUrl = productUrls[String(sku)] ?? productUrls[sku];
        const displayName = productNames[String(sku)] ?? productNames[sku] ?? productName.trim();
        const linkStyle = `color: ${linkColor}; text-decoration: underline; font-weight: 500; cursor: pointer;`;
        if (!productUrl) {
            return displayName;
        }
        return `<a href="${productUrl}"${skuAttr(sku)} style="${linkStyle}">${displayName}</a>`;
    });

    // Product shortcode format 2: [Product Name](sku="SKU")
    result = result.replace(/\[([^\]]+)\]\(sku=['"]([^'"]+)['"]\)/g, (_match: string, productName: string, sku: string) => {
        const productUrl = productUrls[String(sku)] ?? productUrls[sku];
        const displayName = productNames[String(sku)] ?? productNames[sku] ?? productName.trim();
        const linkStyle = `color: ${linkColor}; text-decoration: underline; font-weight: 500; cursor: pointer;`;
        if (!productUrl) {
            return displayName;
        }
        return `<a href="${productUrl}"${skuAttr(sku)} style="${linkStyle}">${displayName}</a>`;
    });

    // Product shortcode format 3: [Product Name SKU: XX]
    result = result.replace(/\[(.+?)\s+SKU:\s*(\d+)\]/g, (_match: string, productName: string, sku: string) => {
        const productUrl = productUrls[String(sku)] ?? productUrls[sku];
        const displayName = productNames[String(sku)] ?? productNames[sku] ?? productName.trim();
        const linkStyle = `color: ${linkColor}; text-decoration: underline; font-weight: 500; cursor: pointer;`;
        if (!productUrl) {
            return displayName;
        }
        return `<a href="${productUrl}"${skuAttr(sku)} style="${linkStyle}">${displayName}</a>`;
    });

    // Fallback: Strip any remaining unmatched product tags
    result = result.replace(/\[product[^\]]*\]([^[]*)\[\/product\]/gi, '$1');

    // Standard markdown links: [text](url)
    result = result.replace(/\[([^\]]+)\]\((?!sku=)([^)]+)\)/g, (_match: string, text: string, url: string) => {
        // Block paths that look like LLM hallucinated URLs (e.g. /URL, /undefined, relative paths without real routes)
        const invalidPathPattern = /^\/(URL|url|undefined|null|#|about:)/i;
        if (invalidPathPattern.test(url)) {
            return `<strong>${text}</strong>`;
        }

        const linkStyle = `color: ${linkColor}; text-decoration: underline;`;
        return `<a href="${url}"${skuAttr(skuByUrl[url])} style="${linkStyle}">${text}</a>`;
    });

    // Bold: **text** or __text__
    result = result.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    result = result.replace(/__([^_]+)__/g, '<strong>$1</strong>');

    // Inline code: `code`
    result = result.replace(/`([^`]+)`/g, '<code style="background: #f0f0f0; padding: 2px 6px; border-radius: 4px; font-family: monospace;">$1</code>');

    // Block-level parsing: walk line-by-line, group list items, paragraphs, and blank lines.
    // Keeps <li> properly wrapped in <ul>/<ol> and prevents block elements from being
    // nested inside <p> (browsers auto-close <p> on block children, producing invalid DOM).
    //
    // Supports one level of nesting: when the LLM emits a sub-list of a different type
    // without indentation (e.g. bullets under a numbered step), attach it to the previous
    // top-level item instead of starting a sibling list — otherwise numbering restarts.
    // Blank lines keep the surrounding list open; only non-list text content closes it.
    const UL_STYLE = 'margin: 8px 0; padding-left: 20px;';
    const OL_STYLE = 'margin: 8px 0; padding-left: 24px;';
    const lines = result.split('\n');
    const blocks: string[] = [];
    type ListBuf = { tag: 'ul' | 'ol'; items: string[] };
    let root: ListBuf | null = null;
    let sub: ListBuf | null = null;
    let paraBuf: string[] = [];

    const renderList = (list: ListBuf): string => {
        const style = list.tag === 'ul' ? UL_STYLE : OL_STYLE;
        const items = list.items.map(it => `<li>${it}</li>`).join('');
        return `<${list.tag} style="${style}">${items}</${list.tag}>`;
    };
    const flushSub = (): void => {
        if (!sub || !root || root.items.length === 0) { sub = null; return; }
        const lastIdx = root.items.length - 1;
        root.items[lastIdx] = root.items[lastIdx] + renderList(sub);
        sub = null;
    };
    const flushRoot = (): void => {
        flushSub();
        if (!root) return;
        blocks.push(renderList(root));
        root = null;
    };
    const flushPara = (): void => {
        if (paraBuf.length === 0) return;
        blocks.push(`<p>${paraBuf.join('<br>')}</p>`);
        paraBuf = [];
    };
    const appendItem = (tag: 'ul' | 'ol', content: string): void => {
        if (!root) {
            root = { tag, items: [content] };
            return;
        }
        if (sub) {
            if (sub.tag === tag) {
                sub.items.push(content);
            } else {
                // Only 'ul' | 'ol' exist, and sub.tag !== root.tag by construction,
                // so tag !== sub.tag implies tag === root.tag → return to parent level.
                flushSub();
                root.items.push(content);
            }
            return;
        }
        if (root.tag === tag) {
            root.items.push(content);
        } else {
            // Different type with no active sub → nest this new list under the last root item.
            sub = { tag, items: [content] };
        }
    };

    for (const rawLine of lines) {
        const ulMatch = rawLine.match(/^\s*[-*]\s+(.+)$/);
        const olMatch = rawLine.match(/^\s*\d+\.\s+(.+)$/);
        const isBlank = rawLine.trim() === '';

        if (ulMatch) {
            flushPara();
            appendItem('ul', ulMatch[1]!);
        } else if (olMatch) {
            flushPara();
            appendItem('ol', olMatch[1]!);
        } else if (isBlank) {
            // Keep any open list context alive across blank lines — LLMs often pad list items
            // with blank lines and we want numbering to stay continuous.
            flushPara();
        } else {
            flushRoot();
            paraBuf.push(rawLine);
        }
    }
    flushPara();
    flushRoot();
    result = blocks.join('');

    // Italic (after lists)
    result = result.replace(/(?<!\w)\*([^*]+)\*(?!\w)/g, '<em>$1</em>');
    result = result.replace(/(?<!\w)_([^_]+)_(?!\w)/g, '<em>$1</em>');

    // Sanitize
    if (shouldSanitize) {
        result = DOMPurify.sanitize(result, {
            ALLOWED_TAGS: ['p', 'br', 'strong', 'em', 'u', 'a', 'ul', 'ol', 'li', 'code'],
            ALLOWED_ATTR: ['href', 'target', 'rel', 'style', 'data-omniguide-sku'],
        });
    }

    return result;
}

/**
 * Parse markdown and return React-safe dangerouslySetInnerHTML object.
 */
export function parseMarkdownToHtml(content: string, options: ParseMarkdownOptions = {}): { __html: string } {
    const html = parseMarkdown(content, options);
    return { __html: html || '' };
}
